    function makeFluidCounts() {
      return Object.fromEntries(FLUID_CELLS.map(c => [c.key, 0]));
    }

    function reticTotal() {
      return Object.values(state.reticulocytes.counts).reduce(function (a, b) { return a + b; }, 0);
    }

    function baarGrade() {
      var total = state.baar.totalBaar;
      var fields = state.baar.fieldsExamined;
      var target = state.baar.targetFields;
      if (fields === 0) return '—';
      var avg = total / fields;
      var done = fields >= target;
      if (!done) {
        if (avg > 10) return '3+ (preliminar)';
        if (avg >= 1) return '2+ (preliminar)';
        return fields + '/' + target + ' campos';
      }
      if (total === 0) return 'Negativo';
      if (target >= 100 && total <= 9) return 'Escasso · ' + total + ' BAAR';
      if (avg < 1) return '1+';
      if (avg <= 10) return '2+';
      return '3+';
    }

    function addBaarInField() {
      if (state.baar.fieldsExamined >= state.baar.targetFields) { beep('long'); showToast('Campos alvo atingidos. Abra o Resumo.'); return; }
      state.baar.currentField += 1;
      state.baar.totalBaar += 1;
      beep('short');
      render();
    }

    function baarNextField() {
      if (state.baar.fieldsExamined >= state.baar.targetFields) { beep('long'); showToast('Campos alvo atingidos. Abra o Resumo.'); return; }
      state.baar.history.push(state.baar.currentField);
      state.baar.fieldsExamined += 1;
      state.baar.currentField = 0;
      var remaining = state.baar.targetFields - state.baar.fieldsExamined;
      if (remaining === 0) { beep('long'); showToast('Baciloscopia concluída · ' + baarGrade()); }
      else { beep('short'); showToast('Campo ' + state.baar.fieldsExamined + ' registrado · faltam ' + remaining); }
      render();
    }



