    (function restoreTrainingState() {
      try {
        var saved = localStorage.getItem('nyx_training_v2');
        if (saved) {
          var t = JSON.parse(saved);
          if (t && t.area) return;
        }
        localStorage.removeItem('nyx_training_v1');
      } catch(e) {}
    })();

    let audioCtx = null;
    let toastTimer = null;
    let wakeLock = null;
    let lastFullscreenTry = 0;
    let fullscreenRetryTimer = null;
    let fullscreenRetryCount = 0;
    let autoFullscreenEnabled = true;

    let appHistoryStarted = false;
    let suppressNextHistoryPush = false;

    const hud = document.getElementById('hud');
    const grid = document.getElementById('grid');
    const toast = document.getElementById('toast');
    const homeScreen = document.getElementById('homeScreen');
    const timerAdjustModal = document.getElementById('timerAdjustModal');
    const closeTimerAdjust = document.getElementById('closeTimerAdjust');
    const applyTimerAdjust = document.getElementById('applyTimerAdjust');
    const resetTimerAdjust = document.getElementById('resetTimerAdjust');
    const manualCronoBtn = document.getElementById('manualCronoBtn');
    const timerMinutes = document.getElementById('timerMinutes');
    const timerSeconds = document.getElementById('timerSeconds');
    const fullscreenBtn = document.getElementById('fullscreenBtn');
    const summaryModal = document.getElementById('summaryModal');
    const summaryContent = document.getElementById('summaryContent');
    const closeSummary = document.getElementById('closeSummary');
    const calcHelpModal = document.getElementById('calcHelpModal');
    const calcHelpContent = document.getElementById('calcHelpContent');
    const closeCalcHelp = document.getElementById('closeCalcHelp');
    const fluidConfigModal = document.getElementById('fluidConfigModal');
    const fluidConfigTitle = document.getElementById('fluidConfigTitle');
    const fluidConfigDescription = document.getElementById('fluidConfigDescription');
    const fluidConfigBody = document.getElementById('fluidConfigBody');
    const fluidConfigError = document.getElementById('fluidConfigError');
    const closeFluidConfig = document.getElementById('closeFluidConfig');
    const cancelFluidConfig = document.getElementById('cancelFluidConfig');
    const applyFluidConfig = document.getElementById('applyFluidConfig');

    function isIOS() {
      return /iPad|iPhone|iPod/.test(navigator.userAgent) || 
        (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1);
    }

    function isLandscape() {
      return window.innerWidth > window.innerHeight;
    }

    function isFullscreen() {
      return Boolean(document.fullscreenElement);
    }

    function total(obj) {
      return Object.values(obj).reduce((a, b) => a + b, 0);
    }

    function hematoTotal() {
      return HEMATO_CELLS
        .filter(cell => !cell.separate)
        .reduce((acc, cell) => acc + (state.hemato.counts[cell.key] || 0), 0);
    }

    function hematoSeparateTotal() {
      return HEMATO_CELLS
        .filter(cell => cell.separate)
        .reduce((acc, cell) => acc + (state.hemato.counts[cell.key] || 0), 0);
    }

    function urineTotal() {
      return total(state.urine.counts);
    }

    function myeloTotal() {
      return total(state.myelo.counts);
    }

    function myeloGroupTotal(group) {
      return MYELO_CELLS
        .filter(cell => cell.group === group)
        .reduce((acc, cell) => acc + (state.myelo.counts[cell.key] || 0), 0);
    }

    function myeloMyeloidTotal() {
      return MYELO_CELLS
        .filter(cell => cell.group === 'myeloid' || cell.group === 'blast')
        .reduce((acc, cell) => acc + (state.myelo.counts[cell.key] || 0), 0);
    }

    function myeloErythroidTotal() {
      return myeloGroupTotal('erythroid');
    }

    function myeloRatioME() {
      const e = myeloErythroidTotal();
      if (!e) return '—';
      return fmt(myeloMyeloidTotal() / e, 2) + ':1';
    }


    function colonyDilutionValue() {
      const exp = parseFloat(String(state.colonies.dilutionExp || '').replace(',', '.'));
      if (!Number.isFinite(exp)) return null;
      return Math.pow(10, -Math.abs(exp));
    }

    function colonyPlatedVolume() {
      const vol = parseFloat(String(state.colonies.platedVolume || '').replace(',', '.'));
      if (!Number.isFinite(vol) || vol <= 0) return null;
      return vol;
    }

    function colonyLoopVolumeMl() {
      const ul = parseFloat(String(state.colonies.loopVolumeUl || '').replace(',', '.'));
      if (!Number.isFinite(ul) || ul <= 0) return null;
      return ul / 1000;
    }

    function colonyActiveCount() {
      return state.colonies.activePlate === 'B' ? (state.colonies.countB || 0) : (state.colonies.count || 0);
    }

    function colonySetActiveCount(value) {
      const v = Math.max(0, value || 0);
      if (state.colonies.activePlate === 'B') state.colonies.countB = v;
      else state.colonies.count = v;
    }

    function colonyCountsForResult() {
      const a = state.colonies.count || 0;
      const b = state.colonies.countB || 0;

      if (state.colonies.plateMode === 'duplicate') {
        const values = [];
        if (a > 0) values.push(a);
        if (b > 0) values.push(b);
        if (!values.length) return { values: [0], average: 0 };
        return { values, average: values.reduce((acc, value) => acc + value, 0) / values.length };
      }

      return { values: [a], average: a };
    }

    function colonyCfuMl() {
      const info = colonyCountsForResult();
      const colonies = info.average;
      if (!colonies) return null;

      if (state.colonies.method === 'loop') {
        const loopMl = colonyLoopVolumeMl();
        if (!loopMl) return null;
        return colonies / loopMl;
      }

      const dilution = colonyDilutionValue();
      const volume = colonyPlatedVolume();
      if (!dilution || !volume) return null;
      return colonies / (dilution * volume);
    }

    function colonyCountStatusFor(n) {
      const min = parseInt(state.colonies.rangeMin || 30, 10);
      const max = parseInt(state.colonies.rangeMax || 300, 10);
      if (!n) return 'Sem colônias contadas';
      if (n < min) return 'Abaixo da faixa ' + min + '–' + max;
      if (n <= max) return 'Faixa ' + min + '–' + max;
      return 'Acima de ' + max;
    }

    function colonyCountStatus() {
      return colonyCountStatusFor(colonyCountsForResult().average || 0);
    }

    function colonyDilutionLabel() {
      const exp = parseFloat(String(state.colonies.dilutionExp || '').replace(',', '.'));
      if (!Number.isFinite(exp)) return '—';
      return exp === 0 ? '10⁰' : '10⁻' + Math.abs(exp);
    }

    function colonyFormulaLabel() {
      if (state.colonies.method === 'loop') return 'UFC/mL = colônias ÷ (alça em uL ÷ 1000)';
      return 'UFC/mL = colônias ÷ (volume plaqueado × diluição)';
    }

    function addColonies(delta) {
      const before = colonyActiveCount();
      colonySetActiveCount(Math.max(0, before + delta));
      state.colonies.history.push({ plate: state.colonies.activePlate || 'A', delta });
      beep(delta > 0 ? 'short' : 'long');
      render();
    }

    function percent(value, denominator) {
      if (!denominator) return '0%';
      const p = (value / denominator) * 100;
      return p % 1 === 0 ? `${p.toFixed(0)}%` : `${p.toFixed(1)}%`;
    }

    function ensureAudio() {
      if (!audioCtx) audioCtx = new (window.AudioContext || window.webkitAudioContext)();
      if (audioCtx.state === 'suspended') audioCtx.resume();
    }

    async function requestWakeLock() {
      try {
        if ('wakeLock' in navigator && !wakeLock) {
          wakeLock = await navigator.wakeLock.request('screen');
        }
      } catch (err) {}
    }

    function vibrate(pattern) {
      if (!state.vibration || !navigator.vibrate) return;
      navigator.vibrate(pattern);
    }

    function beep(kind = 'short') {
      if (state.sound) {
        try {
          ensureAudio();

          const now = audioCtx.currentTime;
          const osc = audioCtx.createOscillator();
          const gain = audioCtx.createGain();

          const duration = kind === 'long' ? 0.50 : 0.052;
          const freq = kind === 'long' ? 510 : 940;

          osc.type = kind === 'long' ? 'triangle' : 'sine';
          osc.frequency.setValueAtTime(freq, now);
          if (kind === 'long') osc.frequency.exponentialRampToValueAtTime(720, now + duration * 0.68);

          gain.gain.setValueAtTime(0.0001, now);
          gain.gain.exponentialRampToValueAtTime(kind === 'long' ? 0.22 : 0.14, now + 0.012);
          gain.gain.exponentialRampToValueAtTime(0.0001, now + duration);

          osc.connect(gain);
          gain.connect(audioCtx.destination);
          osc.start(now);
          osc.stop(now + duration + 0.02);
        } catch (err) {}
      }

      vibrate(kind === 'long' ? [70, 30, 120] : 18);
    }

    async function enterFullscreen(silent = false) {
      if (isIOS()) {
        fullscreenBtn.classList.remove('show');
        stopFullscreenRetries();
        return false;
      }

      if (!isLandscape()) {
        fullscreenBtn.classList.remove('show');
        stopFullscreenRetries();
        return false;
      }

      if (isFullscreen()) {
        fullscreenBtn.classList.remove('show');
        stopFullscreenRetries();
        return true;
      }

      const now = Date.now();
      if (now - lastFullscreenTry < 180) return false;
      lastFullscreenTry = now;

      try {
        await requestWakeLock();

        const el = document.documentElement;
        const request =
          el.requestFullscreen ||
          el.webkitRequestFullscreen ||
          el.mozRequestFullScreen ||
          el.msRequestFullscreen;

        if (request) {
          await request.call(el);
        }

        fullscreenBtn.classList.remove('show');
        stopFullscreenRetries();

        if (!silent) beep('short');
        return true;
      } catch (err) {
        if (isLandscape() && !isFullscreen()) {
          fullscreenBtn.classList.add('show');
          if (!silent) showToast('Toque em “Tela cheia”');
        }
        return false;
      }
    }

    function stopFullscreenRetries() {
      if (fullscreenRetryTimer) {
        clearInterval(fullscreenRetryTimer);
        fullscreenRetryTimer = null;
      }
      fullscreenRetryCount = 0;
    }

    function scheduleLandscapeFullscreen() {
      if (isIOS()) {
        updateFullscreenButton();
        return;
      }

      if (!autoFullscreenEnabled || !isLandscape() || isFullscreen()) {
        updateFullscreenButton();
        return;
      }

      enterFullscreen(true);

      stopFullscreenRetries();
      fullscreenRetryTimer = setInterval(() => {
        fullscreenRetryCount += 1;

        if (!isLandscape() || isFullscreen() || fullscreenRetryCount > 12) {
          stopFullscreenRetries();
          updateFullscreenButton();
          return;
        }

        enterFullscreen(true);
      }, 320);
    }

    function updateFullscreenButton() {
      if (!isIOS() && isLandscape() && !isFullscreen()) {
        fullscreenBtn.classList.add('show');
      } else {
        fullscreenBtn.classList.remove('show');
      }
    }

    function showToast(text) {
      toast.textContent = text;
      toast.classList.add('show');
      clearTimeout(toastTimer);
      toastTimer = setTimeout(() => toast.classList.remove('show'), 1050);
    }


    function fluidType() {
      const id = state.fluids.type || 'ascitic';
      return FLUID_TYPES.find(function (item) { return item.id === id; }) || FLUID_TYPES[2];
    }

    function fluidTotal() {
      return FLUID_CELLS.reduce(function (sum, cell) {
        return sum + (Number(state.fluids.counts[cell.key]) || 0);
      }, 0);
    }

    function fluidTotalNucleated() {
      const value = parseFloat(String(state.fluids.totalNucleated || '').replace(',', '.'));
      return Number.isFinite(value) && value >= 0 ? value : null;
    }

    function fluidPercent(key) {
      const total = fluidTotal();
      if (!total) return 0;
      return ((Number(state.fluids.counts[key]) || 0) / total) * 100;
    }

    function fluidAbsolute(key) {
      const totalNucleated = fluidTotalNucleated();
      if (totalNucleated === null) return null;
      return totalNucleated * fluidPercent(key) / 100;
    }

    function fluidSummaryWarnings() {
      const warnings = [];
      const type = fluidType().id;
      const total = fluidTotal();
      const pmnAbs = fluidAbsolute('neutrophils');
      const atypical = Number(state.fluids.counts.atypical) || 0;
      const crystals = Number(state.fluids.counts.crystals) || 0;

      if (!total) warnings.push('Nenhuma célula diferencial contada.');

      if (type === 'ascitic' && Number.isFinite(pmnAbs) && pmnAbs >= 250) {
        warnings.push('Ascítico: PMN absoluto ≥250/µL. Alerta didático para correlação com PBE e POP local.');
      }

      if (type === 'synovial' && crystals > 0) {
        warnings.push('Sinovial: cristais contados. Confirmar morfologia/polarização conforme método disponível.');
      }

      if (atypical > 0) {
        warnings.push('Células atípicas registradas. Recomenda-se revisão morfológica/supervisão e correlação citológica.');
      }

      return warnings;
    }


    function fuchsDilution() {
      const value = parseFloat(String(state.fluids.fuchs.dilution || '1').replace(',', '.'));
      return Number.isFinite(value) && value > 0 ? value : 1;
    }

    function fuchsAreaMode() {
      const mode = state.fluids.fuchs.areaMode || 'total';
      return ['field', 'quadrant', 'total'].indexOf(mode) >= 0 ? mode : 'total';
    }

    function fuchsAreaModeLabel() {
      const mode = fuchsAreaMode();
      if (mode === 'field') return 'Campo';
      if (mode === 'quadrant') return 'Quadrante';
      return 'Câmara total';
    }

    function fuchsAreaCount() {
      const mode = fuchsAreaMode();

      if (mode === 'total') return 256;

      const fallback = mode === 'quadrant' ? 16 : 256;
      const max = mode === 'quadrant' ? 16 : 256;
      const value = parseFloat(String(state.fluids.fuchs.areaCount || fallback).replace(',', '.'));

      if (!Number.isFinite(value) || value <= 0) return fallback;
      return Math.min(max, Math.max(1, value));
    }

    function fuchsEquivalentFields() {
      const mode = fuchsAreaMode();

      if (mode === 'total') return 256;
      if (mode === 'quadrant') return fuchsAreaCount() * 16;
      return fuchsAreaCount();
    }

    function fuchsEquivalentQuadrants() {
      return fuchsEquivalentFields() / 16;
    }

    function fuchsVolumeUl() {
      // Câmara de Fuchs-Rosenthal: 256 campos no retículo completo.
      // Retículo completo = 16 quadrantes = 256 campos = 3,2 µL.
      // Cada quadrante = 0,2 µL. Cada campo = 0,0125 µL.
      return fuchsEquivalentFields() * 0.0125;
    }

    function fuchsCellsPerUl(kind) {
      const raw = Number(state.fluids.fuchs[kind]) || 0;
      const volume = fuchsVolumeUl();
      const dilution = fuchsDilution();
      if (!volume) return 0;
      return raw * dilution / volume;
    }

    function adjustFuchs(kind, delta) {
      state.fluids.fuchs[kind] = Math.max(0, (Number(state.fluids.fuchs[kind]) || 0) + delta);
      state.fluids.fuchs.history.push({ kind, delta });
      beep('short');
      render();
    }

    function resetFuchs() {
      state.fluids.fuchs.leukocytes = 0;
      state.fluids.fuchs.rbcs = 0;
      state.fluids.fuchs.history = [];
      beep('short');
      render();
    }

    function undoFuchs() {
      const last = state.fluids.fuchs.history.pop();
      if (!last) return;
      state.fluids.fuchs[last.kind] = Math.max(0, (Number(state.fluids.fuchs[last.kind]) || 0) - last.delta);
      beep('short');
      render();
    }

    function setFuchsAreaMode(mode) {
      state.fluids.fuchs.areaMode = mode;

      if (mode === 'total') state.fluids.fuchs.areaCount = '256';
      else if (mode === 'quadrant') state.fluids.fuchs.areaCount = '16';
      else state.fluids.fuchs.areaCount = '256';

      beep('short');
      render();
    }


    let activeFluidConfig = null;

    function fluidModalNumberValue() {
      const input = document.getElementById('fluidConfigInput');
      return input ? String(input.value || '').trim().replace(',', '.') : '';
    }

    function showFluidConfigError(message) {
      fluidConfigError.textContent = message || '';
      fluidConfigError.classList.toggle('show', Boolean(message));
    }

    function closeFluidConfigModal() {
      fluidConfigModal.classList.remove('show');
      fluidConfigModal.setAttribute('aria-hidden', 'true');
      fluidConfigBody.innerHTML = '';
      showFluidConfigError('');
      activeFluidConfig = null;
      beep('short');
    }

    function renderFluidChoiceOptions(options, selectedValue) {
      return '<div class="fluid-choice-grid">' + options.map(function (option) {
        const active = option.value === selectedValue ? ' active' : '';
        return '<button class="fluid-choice-btn' + active + '" type="button" data-fluid-choice="' + option.value + '">' +
          '<b>' + option.label + '</b>' +
          '<span>' + option.help + '</span>' +
        '</button>';
      }).join('') + '</div>';
    }

    function openFluidConfigModal(config) {
      activeFluidConfig = Object.assign({ kind: 'number', value: '', min: null, max: null, emptyAllowed: false }, config || {});

      fluidConfigTitle.textContent = activeFluidConfig.title || 'Configurar líquidos';
      fluidConfigDescription.textContent = activeFluidConfig.description || 'Ajuste o parâmetro selecionado.';
      showFluidConfigError('');

      if (activeFluidConfig.kind === 'choice') {
        fluidConfigBody.innerHTML = renderFluidChoiceOptions(activeFluidConfig.options || [], activeFluidConfig.value);
        Array.prototype.forEach.call(fluidConfigBody.querySelectorAll('[data-fluid-choice]'), function (btn) {
          btn.addEventListener('click', function () {
            activeFluidConfig.value = this.getAttribute('data-fluid-choice');
            Array.prototype.forEach.call(fluidConfigBody.querySelectorAll('[data-fluid-choice]'), function (item) {
              item.classList.toggle('active', item === btn);
            });
          });
        });
      } else {
        const inputType = activeFluidConfig.integer ? 'number' : 'text';
        const inputMode = activeFluidConfig.integer ? 'numeric' : 'decimal';
        const currentValue = activeFluidConfig.value == null ? '' : String(activeFluidConfig.value);
        const help = activeFluidConfig.help ? '<small>' + activeFluidConfig.help + '</small>' : '';

        fluidConfigBody.innerHTML =
          '<label class="fluid-config-field">' +
            '<span>' + (activeFluidConfig.inputLabel || 'Valor') + '</span>' +
            '<input id="fluidConfigInput" type="' + inputType + '" inputmode="' + inputMode + '" value="' + currentValue + '" autocomplete="off" />' +
            help +
          '</label>';
      }

      fluidConfigModal.classList.add('show');
      fluidConfigModal.setAttribute('aria-hidden', 'false');

      setTimeout(function () {
        const input = document.getElementById('fluidConfigInput');
        if (input) {
          input.focus();
          input.select();
        }
      }, 80);

      beep('short');
    }

    function applyFluidConfigModal() {
      if (!activeFluidConfig) return;

      if (activeFluidConfig.kind === 'choice') {
        if (!activeFluidConfig.value) {
          showFluidConfigError('Selecione uma opção.');
          return;
        }

        activeFluidConfig.apply(activeFluidConfig.value);
        fluidConfigModal.classList.remove('show');
        fluidConfigModal.setAttribute('aria-hidden', 'true');
        fluidConfigBody.innerHTML = '';
        showFluidConfigError('');
        activeFluidConfig = null;
        beep('short');
        render();
        return;
      }

      let normalized = fluidModalNumberValue();

      if (!normalized && activeFluidConfig.emptyAllowed) {
        activeFluidConfig.apply('');
        fluidConfigModal.classList.remove('show');
        fluidConfigModal.setAttribute('aria-hidden', 'true');
        fluidConfigBody.innerHTML = '';
        showFluidConfigError('');
        activeFluidConfig = null;
        beep('short');
        render();
        return;
      }

      const parsed = parseFloat(normalized);

      if (!normalized || !Number.isFinite(parsed)) {
        showFluidConfigError('Digite um número válido.');
        return;
      }

      if (activeFluidConfig.min !== null && parsed < activeFluidConfig.min) {
        showFluidConfigError('O valor mínimo permitido é ' + activeFluidConfig.min + '.');
        return;
      }

      if (activeFluidConfig.max !== null && parsed > activeFluidConfig.max) {
        showFluidConfigError('O valor máximo permitido é ' + activeFluidConfig.max + '.');
        return;
      }

      if (activeFluidConfig.integer && !Number.isInteger(parsed)) {
        showFluidConfigError('Use número inteiro.');
        return;
      }

      if (activeFluidConfig.formatter) normalized = activeFluidConfig.formatter(parsed);
      else normalized = String(parsed);

      activeFluidConfig.apply(normalized, parsed);

      fluidConfigModal.classList.remove('show');
      fluidConfigModal.setAttribute('aria-hidden', 'true');
      fluidConfigBody.innerHTML = '';
      showFluidConfigError('');
      activeFluidConfig = null;
      beep('short');
      render();
    }

    function openFuchsConfigModal(field) {
      if (field === 'areaMode') {
        const current = fuchsAreaMode();

        openFluidConfigModal({
          kind: 'choice',
          title: 'Área contada na Fuchs',
          description: 'Escolha como a área lida na câmara será informada. A câmara total equivale a 256 campos, 16 quadrantes e 3,2 µL.',
          value: current,
          options: [
            { value: 'field', label: 'Campo', help: 'Informe quantos campos individuais foram contados.' },
            { value: 'quadrant', label: 'Quadrante', help: 'Informe quantos quadrantes foram contados. 1 quadrante = 16 campos.' },
            { value: 'total', label: 'Câmara total', help: 'Usa automaticamente 256 campos = 16 quadrantes = 3,2 µL.' }
          ],
          apply: function (mode) {
            state.fluids.fuchs.areaMode = mode;
            if (mode === 'total') state.fluids.fuchs.areaCount = '256';
            else if (mode === 'quadrant') state.fluids.fuchs.areaCount = '16';
            else state.fluids.fuchs.areaCount = '256';
          }
        });
        return;
      }

      if (field === 'dilution') {
        openFluidConfigModal({
          kind: 'number',
          title: 'Diluição Fuchs',
          description: 'Informe o fator de diluição aplicado antes da contagem. Sem diluição, use 1.',
          inputLabel: 'Fator de diluição',
          value: state.fluids.fuchs.dilution || '1',
          min: 0.000001,
          help: 'Ex.: amostra sem diluição = 1; diluição 1:10 = fator 10.',
          formatter: function (parsed) { return String(parsed); },
          apply: function (value) {
            state.fluids.fuchs.dilution = value;
          }
        });
        return;
      }

      if (field === 'areaCount') {
        const mode = fuchsAreaMode();

        if (mode === 'total') {
          showToast('Câmara total = 256 campos');
          return;
        }

        const max = mode === 'quadrant' ? 16 : 256;
        const fallback = mode === 'quadrant' ? '16' : '256';

        openFluidConfigModal({
          kind: 'number',
          integer: false,
          title: mode === 'quadrant' ? 'Quadrantes contados' : 'Campos contados',
          description: mode === 'quadrant'
            ? 'Informe quantos quadrantes da Fuchs foram contados. Máximo: 16.'
            : 'Informe quantos campos da Fuchs foram contados. Máximo: 256.',
          inputLabel: mode === 'quadrant' ? 'Número de quadrantes' : 'Número de campos',
          value: state.fluids.fuchs.areaCount || fallback,
          min: 0.000001,
          max: max,
          help: mode === 'quadrant'
            ? '1 quadrante = 16 campos = 0,2 µL.'
            : '1 campo = 0,0125 µL.',
          formatter: function (parsed) { return String(parsed); },
          apply: function (value) {
            state.fluids.fuchs.areaCount = value;
          }
        });
      }
    }

    function openFluidTotalModal() {
      openFluidConfigModal({
        kind: 'number',
        title: 'Células nucleadas/µL',
        description: 'Informe a contagem global de células nucleadas por µL para calcular os absolutos do diferencial.',
        inputLabel: 'Células nucleadas por µL',
        value: state.fluids.totalNucleated || '',
        min: 0,
        emptyAllowed: true,
        help: 'Pode ficar vazio. Quando preenchido, o app calcula o absoluto estimado de cada população do diferencial.',
        formatter: function (parsed) { return String(parsed); },
        apply: function (value) {
          state.fluids.totalNucleated = value;
        }
      });
    }


    function addCount(key) {
      if (isLandscape() && !isFullscreen()) enterFullscreen(true);

      if (state.mode === 'hemato') {
        const target = 100;
        const before = hematoTotal();

        if (before >= target) {
          beep('long');
          showToast('Contagem finalizada em 100 células');
          return;
        }

        const cellMeta = HEMATO_CELLS.find(cell => cell.key === key);

        if (cellMeta && cellMeta.separate && before >= target) {
          beep('long');
          showToast('Eritroblastos bloqueados após 100 células');
          return;
        }

        state.hemato.counts[key] += 1;
        state.hemato.history.push(key);

        const after = hematoTotal();

        if (!(cellMeta && cellMeta.separate) && before < target && after === target) {
          beep('long');
          showToast('100 células atingidas');
        } else {
          beep('short');
        }
      } else if (state.mode === 'myelo') {
        const target = state.myelo.target || 500;
        const before = myeloTotal();

        if (before >= target) {
          beep('long');
          showToast('Mielograma finalizado em ' + target + ' células');
          return;
        }

        state.myelo.counts[key] += 1;
        state.myelo.history.push(key);

        const after = myeloTotal();
        if (before < target && after === target) {
          beep('long');
          showToast(target + ' células medulares atingidas');
        } else {
          beep('short');
        }
      } else if (state.mode === 'fluids') {
        state.fluids.counts[key] = (state.fluids.counts[key] || 0) + 1;
        state.fluids.history.push(key);
        beep('short');
      } else if (state.mode === 'semen') {
        var semenTgt = semenTarget();
        var semenBefore = semenActiveTotal();
        var semenCounts = semenActiveCounts();
        var semenHist = semenIsVitality() ? state.semen.vitalityHistory : (semenIsMorphology() ? state.semen.morphHistory : (semenIsRound() ? state.semen.roundHistory : state.semen.history));
        if (!semenHist) { semenHist = []; if (semenIsRound()) state.semen.roundHistory = semenHist; }
        if (!semenIsRound() && semenBefore >= semenTgt) { beep('long'); showToast(semenActiveLabel() + ' finalizada em ' + semenTgt + ' células'); return; }
        semenCounts[key] = (semenCounts[key] || 0) + 1;
        semenHist.push(key);
        var semenAfter = semenActiveTotal();
        if (!semenIsRound() && semenBefore < semenTgt && semenAfter === semenTgt) { beep('long'); showToast(semenTgt + ' espermatozoides contados'); }
        else { beep('short'); }
      } else if (state.mode === 'reticulocytes') {
        var retTarget = state.reticulocytes.target || 1000;
        var retBefore = reticTotal();
        if (retBefore >= retTarget) { beep('long'); showToast('Contagem finalizada em ' + retTarget + ' células'); return; }
        state.reticulocytes.counts[key] += 1;
        state.reticulocytes.history.push(key);
        var retAfter = reticTotal();
        if (retBefore < retTarget && retAfter === retTarget) { beep('long'); showToast(retTarget + ' células atingidas'); }
        else { beep('short'); }
      } else {
        state.urine.counts[key] += 1;
        state.urine.history.push(key);
        beep('short');
      }

      render();
    }
    function undo() {
      if (state.mode === 'hemato') {
        const key = state.hemato.history.pop();
        if (!key) return;
        state.hemato.counts[key] = Math.max(0, state.hemato.counts[key] - 1);
      } else if (state.mode === 'myelo') {
        const key = state.myelo.history.pop();
        if (!key) return;
        state.myelo.counts[key] = Math.max(0, state.myelo.counts[key] - 1);
      } else if (state.mode === 'fluids') {
        const key = state.fluids.history.pop();
        if (!key) return;
        state.fluids.counts[key] = Math.max(0, (state.fluids.counts[key] || 0) - 1);
      } else if (state.mode === 'semen') {
        if (semenIsConcentration() || semenIsFinal()) return;
        var sHist = semenIsVitality() ? state.semen.vitalityHistory : (semenIsMorphology() ? state.semen.morphHistory : (semenIsRound() ? state.semen.roundHistory : state.semen.history));
        var sCounts = semenActiveCounts();
        var sKey = sHist.pop();
        if (!sKey) return;
        if (semenIsMorphology() && String(sKey).indexOf('defect:') === 0) {
          var dKey = String(sKey).slice(7);
          if (!state.semen.defectCounts) state.semen.defectCounts = makeSemenMorphDefectCounts();
          state.semen.defectCounts[dKey] = Math.max(0, (state.semen.defectCounts[dKey] || 0) - 1);
          if (state.semen.defectHistory) state.semen.defectHistory.pop();
        } else {
          sCounts[sKey] = Math.max(0, (sCounts[sKey] || 0) - 1);
        }
      } else if (state.mode === 'reticulocytes') {
        var rKey = state.reticulocytes.history.pop();
        if (!rKey) return;
        state.reticulocytes.counts[rKey] = Math.max(0, state.reticulocytes.counts[rKey] - 1);
      } else if (state.mode === 'baar') {
        if (state.baar.currentField > 0) {
          state.baar.currentField -= 1;
          state.baar.totalBaar = Math.max(0, state.baar.totalBaar - 1);
        } else if (state.baar.history.length > 0) {
          var lastBaar = state.baar.history.pop();
          state.baar.fieldsExamined = Math.max(0, state.baar.fieldsExamined - 1);
          state.baar.totalBaar = Math.max(0, state.baar.totalBaar - lastBaar);
          state.baar.currentField = lastBaar;
        } else return;
      } else {
        const key = state.urine.history.pop();
        if (!key) return;
        state.urine.counts[key] = Math.max(0, state.urine.counts[key] - 1);
      }

      beep('short');
      render();
    }
    function resetCurrent() {
      if (state.mode === 'hemato') {
        state.hemato.counts = Object.fromEntries(HEMATO_CELLS.map(c => [c.key, 0]));
        state.hemato.history = [];
      } else if (state.mode === 'myelo') {
        state.myelo.counts = Object.fromEntries(MYELO_CELLS.map(c => [c.key, 0]));
        state.myelo.history = [];
      } else if (state.mode === 'colonies') {
        state.colonies.count = 0;
        state.colonies.countB = 0;
        state.colonies.history = [];
      } else if (state.mode === 'fluids') {
        state.fluids.counts = makeFluidCounts();
        state.fluids.history = [];
      } else if (state.mode === 'semen') {
        if (semenIsFinal()) { showToast('Escolha uma seção do espermograma para zerar'); return; }
        else if (semenIsConcentration()) { state.semen.concentration = makeSemenConcentration(); }
        else if (semenIsVitality()) { state.semen.vitalityCounts = makeSemenVitalityCounts(); state.semen.vitalityHistory = []; }
        else if (semenIsMorphology()) { state.semen.morphCounts = makeSemenMorphCounts(); state.semen.morphHistory = []; state.semen.defectCounts = makeSemenMorphDefectCounts(); state.semen.defectHistory = []; }
        else if (semenIsRound()) { state.semen.roundCounts = makeSemenRoundCounts(); state.semen.roundHistory = []; }
        else { state.semen.counts = makeSemenCounts(); state.semen.history = []; }
      } else if (state.mode === 'reticulocytes') {
        state.reticulocytes.counts = Object.fromEntries(RETIC_CELLS.map(c => [c.key, 0]));
        state.reticulocytes.history = [];
        state.reticulocytes.rbcTotal = '';
      } else if (state.mode === 'baar') {
        state.baar.totalBaar = 0;
        state.baar.fieldsExamined = 0;
        state.baar.currentField = 0;
        state.baar.history = [];
      } else {
        state.urine.counts = Object.fromEntries(URINE_CELLS.map(c => [c.key, 0]));
        state.urine.history = [];
      }

      beep('short');
      render();
    }
    function subtotal() {
      const stamp = new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });

      if (state.mode === 'hemato') {
        const n = hematoTotal();
        if (!n) return;
        state.hemato.subtotals.unshift({ stamp, total: n, counts: { ...state.hemato.counts } });
        showToast(`Subtotal: ${n} células`);
      } else if (state.mode === 'myelo') {
        const n = myeloTotal();
        if (!n) return;
        state.myelo.subtotals.unshift({ stamp, total: n, counts: { ...state.myelo.counts } });
        showToast(`Subtotal mielograma: ${n}`);
      } else if (state.mode === 'colonies') {
        const info = colonyCountsForResult();
        const n = info.average || 0;
        if (!n) return;
        state.colonies.subtotals.unshift({ stamp, total: n, cfu: colonyCfuMl(), method: state.colonies.method });
        showToast(`Subtotal colônias: ${fmt(n, 1)}`);
      } else if (state.mode === 'fluids') {
        const n = fluidTotal();
        if (!n) return;
        state.fluids.subtotals.unshift({ stamp, total: n, counts: { ...state.fluids.counts }, type: state.fluids.type });
        showToast(`Subtotal líquidos: ${n}`);
      } else if (state.mode === 'semen') {
        var sn = semenActiveTotal();
        if (semenIsFinal()) { showToast('Resumo final não gera subtotal'); return; }
        if (semenIsConcentration()) {
          var conc = semenConcentrationData();
          var cres = semenConcentrationResult();
          var diffText = cres.diffPct === null ? '—' : fmt(cres.diffPct,1) + '%';
          var diffWarn = cres.diffPct !== null && cres.diffPct > 10 ? ' · revisar replicatas/POP' : '';
          grid.className = 'grid semen-grid semen-concentration-grid';
          grid.innerHTML = '<section class="semen-concentration-panel">' +
            '<article class="semen-conc-card"><h3>Concentração espermática</h3><p>Calculadora educacional baseada em contagem manual. Fórmula: contagem média × diluição ÷ volume contado (µL). Informe o volume real da área/câmara conforme POP.</p><div class="semen-conc-fields">' +
              '<div class="semen-conc-field"><label>Replicata A</label><input id="semenConcA" inputmode="decimal" value="' + escapeHtml(conc.countA || '') + '" placeholder="ex: 100" /></div>' +
              '<div class="semen-conc-field"><label>Replicata B</label><input id="semenConcB" inputmode="decimal" value="' + escapeHtml(conc.countB || '') + '" placeholder="ex: 96" /></div>' +
              '<div class="semen-conc-field"><label>Diluição</label><input id="semenConcDilution" inputmode="decimal" value="' + escapeHtml(conc.dilution || '') + '" placeholder="ex: 20" /></div>' +
              '<div class="semen-conc-field"><label>Volume contado (µL)</label><input id="semenConcVolUl" inputmode="decimal" value="' + escapeHtml(conc.countedVolumeUl || '') + '" placeholder="ex: 0,1" /></div>' +
              '<div class="semen-conc-field"><label>Volume ejaculado (mL)</label><input id="semenConcEjacMl" inputmode="decimal" value="' + escapeHtml(conc.ejaculateVolumeMl || '') + '" placeholder="opcional" /></div>' +
            '</div></article>' +
            '<article class="semen-conc-card"><h3>Resultado</h3><div class="semen-conc-results">' +
              '<div class="semen-conc-line"><span>Média contada</span><strong>' + (cres.mean===null ? '—' : fmt(cres.mean,1)) + '</strong></div>' +
              '<div class="semen-conc-line"><span>Diferença A/B</span><strong>' + diffText + diffWarn + '</strong></div>' +
              '<div class="semen-conc-line"><span>Concentração</span><strong>' + (cres.valid ? fmt(cres.millionMl,2) + ' M/mL' : '—') + '</strong></div>' +
              '<div class="semen-conc-line"><span>Total no ejaculado</span><strong>' + (cres.totalMillion!==null ? fmt(cres.totalMillion,1) + ' milhões' : '—') + '</strong></div>' +
            '</div><div class="semen-conc-actions"><button class="btn danger" id="semenConcClearBtn" type="button">Limpar cálculo</button></div></article>' +
            '<div class="semen-panel-note semen-conc-card full">Use apenas se a câmara, diluição, área/volume contado e rotina local estiverem definidos. Não substitui cálculo validado pelo POP do laboratório.</div>' +
          '</section>';
          [['semenConcA','countA'],['semenConcB','countB'],['semenConcDilution','dilution'],['semenConcVolUl','countedVolumeUl'],['semenConcEjacMl','ejaculateVolumeMl']].forEach(function(pair){
            var el=document.getElementById(pair[0]);
            if(el){el.addEventListener('input',function(){updateSemenConcentrationField(pair[1], this.value);});}
          });
          var clear=document.getElementById('semenConcClearBtn');
          if(clear){clear.addEventListener('click', resetSemenConcentration);}
          return;
        }
        if (!sn) return;
        var semenSubtotal = { stamp: stamp, section: semenSection(), total: sn, counts: Object.assign({}, semenActiveCounts()) };
        if (semenIsMorphology()) semenSubtotal.defects = Object.assign({}, state.semen.defectCounts);
        state.semen.subtotals.unshift(semenSubtotal);
        showToast('Subtotal ' + semenActiveLabel().toLowerCase() + ': ' + sn);
      } else if (state.mode === 'reticulocytes') {
        var rn = reticTotal();
        if (!rn) return;
        state.reticulocytes.subtotals.unshift({ stamp: stamp, total: rn, counts: Object.assign({}, state.reticulocytes.counts) });
        showToast('Subtotal reticulócitos: ' + rn);
      } else if (state.mode === 'baar') {
        var bf = state.baar.fieldsExamined;
        if (!bf) return;
        showToast('Subtotal BAAR: ' + state.baar.totalBaar + ' em ' + bf + ' campos · ' + baarGrade());
      } else {
        const n = urineTotal();
        if (!n) return;
        state.urine.subtotals.unshift({ stamp, total: n, counts: { ...state.urine.counts } });
        showToast(`Subtotal urina: ${n}`);
      }

      beep('long');
      render();
    }
    function setMode(mode) {
      state.mode = mode;
      closeHome();
      beep('short');
      render();
      pushAppRoute();
    }

    function toggleSound() {
      state.sound = !state.sound;
      beep('short');
      render();
    }

    function toggleVibration() {
      state.vibration = !state.vibration;
      beep('short');
      render();
    }


    function openContextualManual() {
      if (state.mode === 'hemato') state.manual.active = 'hemato';
      else if (state.mode === 'myelo') state.manual.active = 'mielograma';
      else if (state.mode === 'urine') state.manual.active = 'urina';
      else if (state.mode === 'colonies') state.manual.active = 'colonias';
      else if (state.mode === 'fluids') state.manual.active = 'liquidos';
      else if (state.mode === 'timer') state.manual.active = 'timer';
      else if (state.mode === 'calc') state.manual.active = 'calculadoras';
      else if (state.mode === 'reticulocytes') state.manual.active = 'reticulocitos';
      else if (state.mode === 'baar') state.manual.active = 'baar';
      else if (state.mode === 'atlas') state.manual.active = 'atlas';
      else if (state.mode === 'training') state.manual.active = 'treino';
      else if (state.mode === 'semen') state.manual.active = 'semen';
      else state.manual.active = 'inicio';

      setMode('manual');
    }

    function setTarget() {
      state.target = 100;
      beep('short');
      render();
    }

    function timerRawElapsedMs() {
      if (!state.timer.running) return state.timer.elapsedMs;
      return state.timer.elapsedMs + (Date.now() - state.timer.startedAt);
    }

    function timerMs() {
      const elapsed = timerRawElapsedMs();

      if (state.timer.mode === 'down') {
        return Math.max(0, state.timer.durationMs - elapsed);
      }

      return elapsed;
    }

    function formatTimer(ms) {
      const totalSeconds = Math.max(0, Math.ceil(ms / 1000));
      const hours = Math.floor(totalSeconds / 3600);
      const minutes = Math.floor((totalSeconds % 3600) / 60);
      const seconds = totalSeconds % 60;

      const mm = String(minutes).padStart(2, '0');
      const ss = String(seconds).padStart(2, '0');

      if (hours > 0) {
        return `${hours}:${mm}:${ss}`;
      }

      return `${mm}:${ss}`;
    }

    function timerLabel() {
      return state.timer.mode === 'down' ? 'Regressivo' : 'Cronômetro';
    }

    function updateTimerDisplay() {
      const value = formatTimer(timerMs());

      Array.prototype.forEach.call(document.querySelectorAll('[data-timer-text]'), function (el) {
        el.textContent = value;
      });

      Array.prototype.forEach.call(document.querySelectorAll('[data-timer-mode]'), function (el) {
        el.textContent = timerLabel();
      });

      Array.prototype.forEach.call(document.querySelectorAll('[data-timer-button]'), function (el) {
        el.textContent = state.timer.running ? 'Pausar' : 'Iniciar';
        el.classList.toggle('active', state.timer.running);
      });

      Array.prototype.forEach.call(document.querySelectorAll('[data-timer-mode-button]'), function (el) {
        el.textContent = state.timer.mode === 'down' ? 'Reg' : 'Crono';
        el.classList.toggle('active', state.timer.mode === 'down');
      });

      if (state.timer.mode === 'down' && state.timer.running && timerMs() <= 0 && !state.timer.alarmed) {
        state.timer.running = false;
        state.timer.elapsedMs = state.timer.durationMs;
        state.timer.startedAt = null;
        state.timer.alarmed = true;
        beep('long');
        showToast('Tempo finalizado');
        render();
      }
    }

    function toggleTimer() {
      if (state.timer.running) {
        state.timer.elapsedMs = timerRawElapsedMs();
        state.timer.running = false;
        state.timer.startedAt = null;
        beep('short');
      } else {
        if (state.timer.mode === 'down' && timerMs() <= 0) {
          state.timer.elapsedMs = 0;
          state.timer.alarmed = false;
        }

        state.timer.running = true;
        state.timer.startedAt = Date.now();
        beep('short');
      }

      render();
    }

    function resetTimer() {
      state.timer.running = false;
      state.timer.startedAt = null;
      state.timer.elapsedMs = 0;
      state.timer.alarmed = false;
      beep('short');
      render();
    }

    function toggleTimerMode() {
      state.timer.running = false;
      state.timer.startedAt = null;
      state.timer.elapsedMs = 0;
      state.timer.alarmed = false;
      state.timer.mode = state.timer.mode === 'down' ? 'up' : 'down';
      beep('short');
      render();
    }

    function setCountdownMinutes(minutes) {
      state.timer.mode = 'down';
      state.timer.running = false;
      state.timer.startedAt = null;
      state.timer.elapsedMs = 0;
      state.timer.durationMs = minutes * 60 * 1000;
      state.timer.alarmed = false;
      beep('short');
      render();
    }

    function cycleCountdownPreset() {
      const presets = [60000, 180000, 300000, 600000];
      const currentIndex = presets.indexOf(state.timer.durationMs);
      const next = presets[(currentIndex + 1) % presets.length];

      state.timer.mode = 'down';
      state.timer.running = false;
      state.timer.startedAt = null;
      state.timer.elapsedMs = 0;
      state.timer.durationMs = next;
      state.timer.alarmed = false;

      beep('short');
      showToast(`Timer regressivo: ${formatTimer(next)}`);
      render();
    }

    function openHome() {
      homeScreen.classList.remove('hidden');
      pushAppRoute();
    }

    function closeHome() {
      homeScreen.classList.add('hidden');
    }

    function currentRouteState() {
      return {
        mode: state.mode,
        home: !homeScreen.classList.contains('hidden'),
        calcActive: state.calc ? state.calc.active : 'menu',
        calcCategory: state.calc ? state.calc.category : 'all',
        manualActive: state.manual ? state.manual.active : 'inicio'
      };
    }

    function pushAppRoute() {
      if (suppressNextHistoryPush) {
        suppressNextHistoryPush = false;
        return;
      }

      if (!window.history || !window.history.pushState) return;

      const route = currentRouteState();

      if (!appHistoryStarted) {
        window.history.replaceState(route, '', window.location.href);
        appHistoryStarted = true;
        return;
      }

      window.history.pushState(route, '', window.location.href);
    }

    function handleSystemBack() {
      if (fluidConfigModal && fluidConfigModal.classList.contains('show')) {
        closeFluidConfigModal();
        return true;
      }

      if (calcHelpModal && calcHelpModal.classList.contains('show')) {
        closeCalcHelpModal();
        return true;
      }

      if (timerAdjustModal && timerAdjustModal.classList.contains('show')) {
        closeTimerAdjustModal();
        return true;
      }

      if (summaryModal && summaryModal.classList.contains('show')) {
        closeModal();
        return true;
      }

      if (!homeScreen.classList.contains('hidden')) {
        return false;
      }

      if (state.mode === 'calc' && state.calc.active && state.calc.active !== 'menu') {
        state.calc.active = 'menu';
        state.calc.activeField = null;
        state.calc.scientific = false;
        render();
        return true;
      }

      if (state.mode === 'calc' && state.calc.category && state.calc.category !== 'all') {
        state.calc.category = 'all';
        render();
        return true;
      }

      homeScreen.classList.remove('hidden');
      render();
      return true;
    }

    function selectModule(mode) {
      if (mode === 'manual') state.manual.active = 'inicio';
      if (mode === 'atlas' && !state.atlas.selected) state.atlas.selected = 'seg';
      if (mode === 'training') { state.training.selected = null; state.training.answered = false; }
      state.mode = mode;
      closeHome();
      beep('short');
      render();
      pushAppRoute();
    }

    window.selectModule = selectModule;

    Array.prototype.forEach.call(document.querySelectorAll('.home-option[data-home-mode], .home-manual-top[data-home-mode]'), function (btn) {
      btn.addEventListener('click', function () {
        selectModule(this.getAttribute('data-home-mode'));
      });
    });



    function openTimerAdjust() {
      const remainingOrElapsed = timerMs();
      let baseMs = state.timer.mode === 'down' ? Math.max(0, remainingOrElapsed) : state.timer.durationMs;

      if (state.timer.mode === 'up') {
        baseMs = 0;
      }

      const totalSeconds = Math.floor(baseMs / 1000);
      timerMinutes.value = Math.floor(totalSeconds / 60);
      timerSeconds.value = totalSeconds % 60;

      timerAdjustModal.classList.add('show');
      timerAdjustModal.setAttribute('aria-hidden', 'false');
      beep('short');
    }

    function closeTimerAdjustModal() {
      timerAdjustModal.classList.remove('show');
      timerAdjustModal.setAttribute('aria-hidden', 'true');
      beep('short');
    }

    function applyManualTimer() {
      const min = Math.max(0, Number(timerMinutes.value) || 0);
      const sec = Math.max(0, Math.min(59, Number(timerSeconds.value) || 0));
      const ms = ((min * 60) + sec) * 1000;

      state.timer.running = false;
      state.timer.startedAt = null;
      state.timer.elapsedMs = 0;
      state.timer.alarmed = false;

      if (ms > 0) {
        state.timer.mode = 'down';
        state.timer.durationMs = ms;
        showToast(`Regressivo ajustado: ${formatTimer(ms)}`);
      } else {
        state.timer.mode = 'up';
        state.timer.durationMs = 300000;
        showToast('Cronômetro ajustado');
      }

      closeTimerAdjustModal();
      render();
    }

    function setManualCronometer() {
      state.timer.mode = 'up';
      state.timer.running = false;
      state.timer.startedAt = null;
      state.timer.elapsedMs = 0;
      state.timer.alarmed = false;
      closeTimerAdjustModal();
      render();
    }

    function resetManualTimerFromModal() {
      resetTimer();
      closeTimerAdjustModal();
    }

    function urineMethodInfo() {
      const methods = {
        neubauer: {
          label: 'Neubauer',
          short: 'Neubauer ×1.000',
          factor: 1000,
          unit: '/mL',
          note: 'Câmara de Neubauer: resultado = contagem × 1.000/mL.'
        },
        kcell9: {
          label: 'K-Cell 9 áreas',
          short: 'K-Cell 9 ×1.000',
          factor: 1000,
          unit: '/mL',
          note: 'K-Cell padrão: contar 9 retículos/círculos e multiplicar por 1.000/mL.'
        },
        kcell1: {
          label: 'K-Cell 1 área',
          short: 'K-Cell 1 ×9.000',
          factor: 9000,
          unit: '/mL',
          note: 'K-Cell em alta celularidade: contar 1 retículo/círculo e multiplicar por 9.000/mL.'
        }
      };

      return methods[state.urineMethod] || methods.neubauer;
    }

    function setUrineMethod(method) {
      state.urineMethod = method;
      beep('short');
      render();
    }

    function renderHud() {
      syncVisualState();
      if (state.mode === 'hemato') {
        const n = hematoTotal();
        const erythroblasts = hematoSeparateTotal();
        const target = 100;
        const progress = Math.min(100, (n / target) * 100);

        hud.innerHTML = `
          <section class="readout-row clean-hud-readout">
            <div class="readout">
              <span class="mode">Hematologia</span>
              <h1 class="total">${n}<small>/${target}</small></h1>
            </div>

            <div class="progress-wrap hemato-progress-wrap">
              <div class="hemato-progress-line">
                <div class="progress compact-progress"><i style="width:${progress}%"></i></div>
                <label class="wbc-hud-field">
                  <span>Leucócitos/µL</span>
                  <input id="hematoWbcInput" inputmode="numeric" pattern="[0-9]*" value="${state.hemato.wbcTotal || ''}" placeholder="ex: 7800" />
                </label>
              </div>
              <div class="status">${n >= target ? 'Finalizado' : 'Em contagem'}${erythroblasts ? ` · Eritroblastos: ${erythroblasts}` : ''}</div>
            </div>
          </section>

          <section class="control-row clean-control-row hemato-actions">
            <button class="btn" id="homeBtn" type="button">Início</button>
            <button class="btn good" id="subtotalBtn" type="button">Sub</button>
            <button class="btn" id="summaryBtn" type="button">Res</button>
            <button class="btn help-mini" id="manualModuleBtn" type="button" aria-label="Ajuda do módulo atual">?</button>
            <button class="btn danger" id="resetBtn" type="button">Zerar</button>
          </section>
        `;
      } else if (state.mode === 'myelo') {
        const n = myeloTotal();
        const target = state.myelo.target || 500;
        const progress = Math.min(100, (n / target) * 100);
        const blastPct = percent(state.myelo.counts.myBlast || 0, n);
        const me = myeloRatioME();

        hud.innerHTML = `
          <section class="readout-row clean-hud-readout">
            <div class="readout">
              <span class="mode">Mielograma</span>
              <h1 class="total">${n}<small>/${target}</small></h1>
            </div>

            <div class="progress-wrap">
              <div class="progress"><i style="width:${progress}%"></i></div>
              <div class="status">${n >= target ? 'Finalizado' : 'Em contagem'} · M:E ${me} · Blastos ${blastPct}</div>
            </div>
          </section>

          <section class="control-row clean-control-row myelo-actions">
            <button class="btn" id="homeBtn" type="button">Início</button>
            <button class="btn ${target === 300 ? 'active' : ''}" id="myeloTarget300" type="button">300</button>
            <button class="btn ${target === 500 ? 'active' : ''}" id="myeloTarget500" type="button">500</button>
            <button class="btn good" id="subtotalBtn" type="button">Sub</button>
            <button class="btn" id="summaryBtn" type="button">Res</button>
            <button class="btn help-mini" id="manualModuleBtn" type="button" aria-label="Ajuda do módulo atual">?</button>
            <button class="btn danger" id="resetBtn" type="button">Zerar</button>
          </section>
        `;
      } else if (state.mode === 'colonies') {
        const n = colonyActiveCount();
        const cfu = colonyCfuMl();
        const status = colonyCountStatus();

        hud.innerHTML = `
          <section class="readout-row clean-hud-readout colony-hud-readout">
            <div class="readout">
              <span class="mode">Colônias</span>
              <h1 class="total">${n}</h1>
            </div>

            <div class="progress-wrap">
              <div class="status">${status}${cfu ? ` · ${fmt(cfu, 0)} UFC/mL` : ''}</div>
              <div class="colony-hud-fields">
                <label class="wbc-hud-field colony-dilution-field ${state.colonies.method === 'loop' ? 'is-disabled' : ''}">
                  <span>Diluição</span>
                  <input id="colonyDilutionInput" inputmode="decimal" value="${state.colonies.dilutionExp || ''}" placeholder="10⁻x" ${state.colonies.method === 'loop' ? 'disabled' : ''} />
                </label>
                <label class="wbc-hud-field colony-volume-field">
                  <span>${state.colonies.method === 'loop' ? 'Alça (uL)' : 'Vol. mL'}</span>
                  <input id="${state.colonies.method === 'loop' ? 'colonyLoopInput' : 'colonyVolumeInput'}" inputmode="decimal" value="${state.colonies.method === 'loop' ? (state.colonies.loopVolumeUl || '') : (state.colonies.platedVolume || '')}" placeholder="${state.colonies.method === 'loop' ? '1' : '0.1'}" />
                </label>
              </div>
            </div>
          </section>

          <section class="control-row clean-control-row colonies-actions">
            <button class="btn" id="homeBtn" type="button">Início</button>
            <button class="btn good" id="subtotalBtn" type="button">Sub</button>
            <button class="btn" id="summaryBtn" type="button">Res</button>
            <button class="btn help-mini" id="manualModuleBtn" type="button" aria-label="Ajuda do módulo atual">?</button>
            <button class="btn danger" id="resetBtn" type="button">Zerar</button>
          </section>
        `;
      } else if (state.mode === 'atlas') {
        const filteredCount = ATLAS_CELLS.length;
        hud.innerHTML = `
          <section class="readout-row clean-hud-readout"><div class="readout"><span class="mode">Atlas</span><h1 class="total">${filteredCount}<small> fichas</small></h1></div><div class="progress-wrap"><div class="progress"><i style="width:100%"></i></div><div class="status">Morfologia, diferenciais e armadilhas de lâmina</div></div></section>
          <section class="control-row clean-control-row atlas-actions"><button class="btn" id="homeBtn" type="button">Início</button><button class="btn help-mini" id="manualModuleBtn" type="button" aria-label="Ajuda do atlas">?</button></section>`;
      } else if (state.mode === 'training') {
        const acc = state.training.totalAnswered ? Math.round((state.training.score / state.training.totalAnswered) * 100) : 0;
        hud.innerHTML = `
          <section class="readout-row clean-hud-readout"><div class="readout"><span class="mode">Treino</span><h1 class="total">${state.training.score}<small>/${state.training.totalAnswered || 0}</small></h1></div><div class="progress-wrap"><div class="progress"><i style="width:${acc}%"></i></div><div class="status">Quiz morfológico · acurácia ${acc}%</div></div></section>
          <section class="control-row clean-control-row training-actions"><button class="btn" id="homeBtn" type="button">Início</button><button class="btn good" id="trainingNextBtn" type="button">Próximo</button><button class="btn help-mini" id="manualModuleBtn" type="button" aria-label="Ajuda do treino">?</button><button class="btn danger" id="trainingResetBtn" type="button">Zerar</button></section>`;
      } else if (state.mode === 'manual') {
        hud.innerHTML = `
          <section class="readout-row clean-hud-readout">
            <div class="readout">
              <span class="mode">Guia</span>
              <h1 class="total">Manual</h1>
            </div>

            <div class="progress-wrap">
              <div class="progress"><i style="width:100%"></i></div>
              <div class="status">Ajuda de uso por módulo</div>
            </div>
          </section>

          <section class="control-row clean-control-row manual-actions">
            <button class="btn" id="homeBtn" type="button">Início</button>
          </section>
        `;
      } else if (state.mode === 'calc') {
        hud.innerHTML = `
          <section class="readout-row clean-hud-readout">
            <div class="readout">
              <span class="mode">Ferramentas</span>
              <h1 class="total">Calc</h1>
            </div>

            <div class="progress-wrap">
              <div class="progress"><i style="width:100%"></i></div>
              <div class="status">Calculadoras e conversores</div>
            </div>
          </section>

          <section class="control-row clean-control-row calc-actions">
            <button class="btn" id="homeBtn" type="button">Início</button>
            <button class="btn help-mini" id="manualModuleBtn" type="button" aria-label="Ajuda das calculadoras">?</button>
          </section>
        `;
      } else if (state.mode === 'timer') {
        const n = timerMs();
        const progress = state.timer.mode === 'down' && state.timer.durationMs
          ? Math.max(0, Math.min(100, (n / state.timer.durationMs) * 100))
          : 100;

        hud.innerHTML = `
          <section class="readout-row clean-hud-readout timer-readout-clean">
            <div class="readout">
              <span class="mode">Timer</span>
              <h1 class="total" data-timer-text>${formatTimer(n)}</h1>
            </div>

            <div class="progress-wrap">
              <div class="progress"><i style="width:${progress}%"></i></div>
              <div class="status">${timerLabel()} · ${state.timer.running ? 'Rodando' : 'Pausado'} · toque no relógio grande para ajustar</div>
            </div>
          </section>

          <section class="control-row clean-control-row timer-actions">
            <button class="btn" id="homeBtn" type="button">Início</button>
            <button class="btn ${state.timer.running ? 'active' : ''}" id="timerBtn" data-timer-button type="button">${state.timer.running ? 'Pausar' : 'Iniciar'}</button>
            <button class="btn ${state.timer.mode === 'down' ? 'active' : ''}" id="timerModeBtn" data-timer-mode-button type="button">${state.timer.mode === 'down' ? 'Reg' : 'Crono'}</button>
            <button class="btn" id="timerPresetBtn" type="button">${state.timer.mode === 'down' ? formatTimer(state.timer.durationMs) : 'Tempo'}</button>
            <button class="btn" id="timerManualBtn" type="button">Ajustar</button>
            <button class="btn help-mini" id="manualModuleBtn" type="button" aria-label="Ajuda do timer">?</button>
            <button class="btn danger" id="timerResetBtn" type="button">Zerar</button>
          </section>
        `;
      } else if (state.mode === 'fluids') {
        const total = fluidTotal();
        const type = fluidType();
        const leukoUl = fuchsCellsPerUl('leukocytes');
        const rbcUl = fuchsCellsPerUl('rbcs');
        const hasFuchs = (Number(state.fluids.fuchs.leukocytes) || 0) || (Number(state.fluids.fuchs.rbcs) || 0);
        const nucleated = state.fluids.totalNucleated || '—';

        hud.innerHTML = `
          <section class="readout-row clean-hud-readout fluids-hud-readout">
            <div class="readout">
              <span class="mode">Líquidos</span>
              <h1 class="total">${total}</h1>
            </div>

            <div class="progress-wrap fluids-hud-progress">
              <div class="progress"><i style="width:${total ? 100 : 0}%"></i></div>
              <div class="status">${type.label} · Nucleadas/µL ${nucleated}${hasFuchs ? ` · Fuchs L ${fmt(leukoUl, 1)}/µL · H ${fmt(rbcUl, 1)}/µL` : ''}</div>
            </div>
          </section>

          <section class="control-row clean-control-row fluids-actions">
            <button class="btn" id="homeBtn" type="button">Início</button>
            <button class="btn good" id="subtotalBtn" type="button">Sub</button>
            <button class="btn" id="summaryBtn" type="button">Res</button>
            <button class="btn help-mini" id="manualModuleBtn" type="button" aria-label="Ajuda do módulo atual">?</button>
            <button class="btn danger" id="resetBtn" type="button">Zerar</button>
          </section>
        `;
      } else if (state.mode === 'semen') {
        var sn2 = semenActiveTotal();
        var stgt = semenTarget();
        var sConc = semenConcentrationResult();
        var sprog = semenIsFinal() ? 100 : (semenIsConcentration() ? (sConc.valid ? 100 : 0) : (semenIsRound() ? (sn2 ? 100 : 0) : Math.min(100, (sn2 / stgt) * 100)));
        var sec = semenSection();
        var totalHtml = semenIsFinal() ? 'Final' : (semenIsConcentration() ? ((sConc.valid ? fmt(sConc.millionMl,1) : '0') + '<small>M/mL</small>') : (semenIsRound() ? (sn2 + '<small>evt</small>') : (sn2 + '<small>/' + stgt + '</small>')));
        hud.innerHTML = '<section class="readout-row clean-hud-readout"><div class="readout"><span class="mode">Espermograma</span><h1 class="total">' + totalHtml + '</h1></div><div class="progress-wrap"><div class="progress"><i style="width:' + sprog + '%"></i></div><div class="status">' + semenActiveLabel() + ' · ' + semenStatus() + '</div></div></section><section class="control-row clean-control-row semen-actions"><button class="btn" id="homeBtn" type="button">Início</button><button class="btn' + (sec==='motility' ? ' active' : '') + '" id="semenMotilityBtn" type="button">Mot</button><button class="btn' + (sec==='vitality' ? ' active' : '') + '" id="semenVitalityBtn" type="button">Vit</button><button class="btn' + (sec==='morphology' ? ' active' : '') + '" id="semenMorphologyBtn" type="button">Morf</button><button class="btn' + (sec==='round' ? ' active' : '') + '" id="semenRoundBtn" type="button">Red</button><button class="btn' + (sec==='concentration' ? ' active' : '') + '" id="semenConcentrationBtn" type="button">Conc</button><button class="btn' + (sec==='final' ? ' active' : '') + '" id="semenFinalBtn" type="button">Final</button><button class="btn good" id="subtotalBtn" type="button">Sub</button><button class="btn" id="summaryBtn" type="button">Res</button><button class="btn help-mini" id="manualModuleBtn" type="button" aria-label="Ajuda do espermograma">?</button><button class="btn danger" id="resetBtn" type="button">Zerar</button></section>';
      } else if (state.mode === 'reticulocytes') {
        var rn2 = reticTotal();
        var rtgt = state.reticulocytes.target || 1000;
        var rcnt = state.reticulocytes.counts.reticulocyte || 0;
        var rpct = rn2 > 0 ? (rcnt / rn2 * 100).toFixed(2) : '0.00';
        var rprog = Math.min(100, (rn2 / rtgt) * 100);
        hud.innerHTML = '<section class="readout-row clean-hud-readout"><div class="readout"><span class="mode">Reticulócitos</span><h1 class="total">' + rn2 + '<small>/' + rtgt + '</small></h1></div><div class="progress-wrap hemato-progress-wrap"><div class="hemato-progress-line"><div class="progress compact-progress"><i style="width:' + rprog + '%"></i></div><label class="wbc-hud-field"><span>Hemácias/µL</span><input id="reticRbcInput" inputmode="numeric" pattern="[0-9]*" value="' + (state.reticulocytes.rbcTotal || '') + '" placeholder="ex: 4500000" /></label></div><div class="status">' + (rn2 >= rtgt ? 'Finalizado' : 'Em contagem') + ' · Retic: ' + rpct + '%</div></div></section><section class="control-row clean-control-row retic-actions"><button class="btn" id="homeBtn" type="button">Início</button><button class="btn good" id="subtotalBtn" type="button">Sub</button><button class="btn" id="summaryBtn" type="button">Res</button><button class="btn help-mini" id="manualModuleBtn" type="button" aria-label="Ajuda de reticulócitos">?</button><button class="btn danger" id="resetBtn" type="button">Zerar</button></section>';
      } else if (state.mode === 'baar') {
        var btgt = state.baar.targetFields;
        var bflds = state.baar.fieldsExamined;
        var btot = state.baar.totalBaar;
        var bgrd = baarGrade();
        var bprog = Math.min(100, (bflds / btgt) * 100);
        hud.innerHTML = '<section class="readout-row clean-hud-readout"><div class="readout"><span class="mode">BAAR</span><h1 class="total">' + bflds + '<small>/' + btgt + '</small></h1></div><div class="progress-wrap"><div class="progress"><i style="width:' + bprog + '%"></i></div><div class="status">' + bgrd + ' · ' + btot + ' BAAR total</div></div></section><section class="control-row clean-control-row baar-actions"><button class="btn" id="homeBtn" type="button">Início</button><button class="btn' + (btgt === 20 ? ' active' : '') + '" id="baarTarget20" type="button">20</button><button class="btn' + (btgt === 50 ? ' active' : '') + '" id="baarTarget50" type="button">50</button><button class="btn' + (btgt === 100 ? ' active' : '') + '" id="baarTarget100" type="button">100</button><button class="btn" id="summaryBtn" type="button">Res</button><button class="btn help-mini" id="manualModuleBtn" type="button" aria-label="Ajuda de BAAR">?</button><button class="btn danger" id="resetBtn" type="button">Zerar</button></section>';
      } else {
        const l = state.urine.counts.urineLeuko;
        const h = state.urine.counts.urineRbc;
        const n = urineTotal();
        const method = urineMethodInfo();

        hud.innerHTML = `
          <section class="readout-row clean-hud-readout">
            <div class="readout">
              <span class="mode">Urina</span>
              <h1 class="total">${n}</h1>
            </div>

            <div class="progress-wrap">
              <div class="progress"><i style="width:${n ? 100 : 0}%"></i></div>
              <div class="status">Leuco ${l} · Hemác ${h} · ${method.short}</div>
            </div>
          </section>

          <section class="control-row clean-control-row urine-actions">
            <button class="btn" id="homeBtn" type="button">Início</button>
            <button class="btn ${state.urineMethod === 'neubauer' ? 'active' : ''}" id="methodNeubauer" type="button">Neubauer</button>
            <button class="btn ${state.urineMethod === 'kcell9' ? 'active' : ''}" id="methodKcell9" type="button">K-Cell 9</button>
            <button class="btn ${state.urineMethod === 'kcell1' ? 'active' : ''}" id="methodKcell1" type="button">K-Cell 1</button>
            <button class="btn good" id="subtotalBtn" type="button">Sub</button>
            <button class="btn" id="summaryBtn" type="button">Res</button>
            <button class="btn help-mini" id="manualModuleBtn" type="button" aria-label="Ajuda do módulo atual">?</button>
            <button class="btn danger" id="resetBtn" type="button">Zerar</button>
          </section>
        `;
      }

      const homeBtn = document.getElementById('homeBtn');
      if (homeBtn) homeBtn.addEventListener('click', openHome);

      const manualModuleBtn = document.getElementById('manualModuleBtn');
      if (manualModuleBtn) manualModuleBtn.addEventListener('click', openContextualManual);

      const subtotalBtn = document.getElementById('subtotalBtn');
      const summaryBtn = document.getElementById('summaryBtn');
      const resetBtn = document.getElementById('resetBtn');

      if (subtotalBtn) subtotalBtn.addEventListener('click', subtotal);
      if (summaryBtn) summaryBtn.addEventListener('click', showSummary);
      if (resetBtn) resetBtn.addEventListener('click', resetCurrent);

      const semenMotilityBtn = document.getElementById('semenMotilityBtn');
      const semenVitalityBtn = document.getElementById('semenVitalityBtn');
      const semenMorphologyBtn = document.getElementById('semenMorphologyBtn');
      const semenRoundBtn = document.getElementById('semenRoundBtn');
      const semenConcentrationBtn = document.getElementById('semenConcentrationBtn');
      const semenFinalBtn = document.getElementById('semenFinalBtn');
      if (semenMotilityBtn) semenMotilityBtn.addEventListener('click', function(){ setSemenSection('motility'); });
      if (semenVitalityBtn) semenVitalityBtn.addEventListener('click', function(){ setSemenSection('vitality'); });
      if (semenMorphologyBtn) semenMorphologyBtn.addEventListener('click', function(){ setSemenSection('morphology'); });
      if (semenRoundBtn) semenRoundBtn.addEventListener('click', function(){ setSemenSection('round'); });
      if (semenConcentrationBtn) semenConcentrationBtn.addEventListener('click', function(){ setSemenSection('concentration'); });
      if (semenFinalBtn) semenFinalBtn.addEventListener('click', function(){ setSemenSection('final'); });

      const hematoWbcInput = document.getElementById('hematoWbcInput');
      if (hematoWbcInput) {
        hematoWbcInput.addEventListener('input', function () {
          state.hemato.wbcTotal = this.value.replace(/[^0-9.,]/g, '').replace(',', '.');
        });
        hematoWbcInput.addEventListener('change', function () {
          state.hemato.wbcTotal = this.value.replace(/[^0-9.,]/g, '').replace(',', '.');
        });
      }

      const colonyDilutionInput = document.getElementById('colonyDilutionInput');
      const colonyVolumeInput = document.getElementById('colonyVolumeInput');
      const colonyLoopInput = document.getElementById('colonyLoopInput');

      if (colonyDilutionInput) {
        colonyDilutionInput.addEventListener('input', function () {
          state.colonies.dilutionExp = this.value.replace(/[^0-9.,]/g, '').replace(',', '.');
        });
        colonyDilutionInput.addEventListener('change', function () {
          state.colonies.dilutionExp = this.value.replace(/[^0-9.,]/g, '').replace(',', '.');
          render();
        });
      }

      if (colonyVolumeInput) {
        colonyVolumeInput.addEventListener('input', function () {
          state.colonies.platedVolume = this.value.replace(/[^0-9.,]/g, '').replace(',', '.');
        });
        colonyVolumeInput.addEventListener('change', function () {
          state.colonies.platedVolume = this.value.replace(/[^0-9.,]/g, '').replace(',', '.');
          render();
        });
      }

      if (colonyLoopInput) {
        colonyLoopInput.addEventListener('input', function () {
          state.colonies.loopVolumeUl = this.value.replace(/[^0-9.,]/g, '').replace(',', '.');
        });
        colonyLoopInput.addEventListener('change', function () {
          state.colonies.loopVolumeUl = this.value.replace(/[^0-9.,]/g, '').replace(',', '.');
          render();
        });
      }

      const myeloTarget300 = document.getElementById('myeloTarget300');
      const myeloTarget500 = document.getElementById('myeloTarget500');
      if (myeloTarget300) myeloTarget300.addEventListener('click', () => { state.myelo.target = 300; beep('short'); render(); });
      if (myeloTarget500) myeloTarget500.addEventListener('click', () => { state.myelo.target = 500; beep('short'); render(); });

      const timerBtn = document.getElementById('timerBtn');
      const timerResetBtn = document.getElementById('timerResetBtn');
      const timerModeBtn = document.getElementById('timerModeBtn');
      const timerPresetBtn = document.getElementById('timerPresetBtn');
      const timerManualBtn = document.getElementById('timerManualBtn');

      if (timerBtn) timerBtn.addEventListener('click', toggleTimer);
      if (timerModeBtn) timerModeBtn.addEventListener('click', toggleTimerMode);
      if (timerPresetBtn) timerPresetBtn.addEventListener('click', cycleCountdownPreset);
      if (timerManualBtn) timerManualBtn.addEventListener('click', openTimerAdjust);
      if (timerResetBtn) timerResetBtn.addEventListener('click', resetTimer);

      const methodNeubauer = document.getElementById('methodNeubauer');
      const methodKcell9 = document.getElementById('methodKcell9');
      const methodKcell1 = document.getElementById('methodKcell1');

      if (methodNeubauer) methodNeubauer.addEventListener('click', () => setUrineMethod('neubauer'));
      if (methodKcell9) methodKcell9.addEventListener('click', () => setUrineMethod('kcell9'));
      if (methodKcell1) methodKcell1.addEventListener('click', () => setUrineMethod('kcell1'));
      var reticRbcInput = document.getElementById('reticRbcInput');
      if (reticRbcInput) {
        reticRbcInput.addEventListener('input', function () { state.reticulocytes.rbcTotal = this.value.replace(/[^0-9.,]/g, '').replace(',', '.'); });
        reticRbcInput.addEventListener('change', function () { state.reticulocytes.rbcTotal = this.value.replace(/[^0-9.,]/g, '').replace(',', '.'); });
      }
      var baarTarget20 = document.getElementById('baarTarget20');
      var baarTarget50 = document.getElementById('baarTarget50');
      var baarTarget100 = document.getElementById('baarTarget100');
      if (baarTarget20) baarTarget20.addEventListener('click', function () { state.baar.targetFields = 20; beep('short'); render(); });
      if (baarTarget50) baarTarget50.addEventListener('click', function () { state.baar.targetFields = 50; beep('short'); render(); });
      if (baarTarget100) baarTarget100.addEventListener('click', function () { state.baar.targetFields = 100; beep('short'); render(); });
      const trainingNextBtn = document.getElementById('trainingNextBtn');
      const trainingResetBtn = document.getElementById('trainingResetBtn');
      if (trainingNextBtn) trainingNextBtn.addEventListener('click', nextTrainingCase);
      if (trainingResetBtn) trainingResetBtn.addEventListener('click', resetTraining);

    }

