    function unitConvType() {
      const raw = calcValue('unit.type') || 'length';
      return Object.prototype.hasOwnProperty.call(UNIT_CONVERTER_GROUPS, raw) ? raw : 'length';
    }

    function unitConvGroup() {
      return UNIT_CONVERTER_GROUPS[unitConvType()];
    }

    function unitConvUnit(kind) {
      const group = unitConvGroup();
      const units = group.units || [];
      const raw = calcValue('unit.' + kind);
      const found = units.find(function (unit) { return unit.id === raw; });
      if (found) return found;
      if (kind === 'to') return units[1] || units[0];
      return units[0];
    }

    function temperatureToC(value, unitId) {
      if (unitId === 'F') return (value - 32) * 5 / 9;
      if (unitId === 'K') return value - 273.15;
      return value;
    }

    function temperatureFromC(value, unitId) {
      if (unitId === 'F') return (value * 9 / 5) + 32;
      if (unitId === 'K') return value + 273.15;
      return value;
    }

    function unitConvertResultData() {
      const value = calcNum('unit.value');
      const type = unitConvType();
      const group = unitConvGroup();
      const from = unitConvUnit('from');
      const to = unitConvUnit('to');

      if (!Number.isFinite(value)) {
        return { ok: false, value, type, group, from, to, result: null };
      }

      let result;
      if (type === 'temperature') {
        const celsius = temperatureToC(value, from.id);
        result = temperatureFromC(celsius, to.id);
      } else {
        const baseValue = value * from.factor;
        result = baseValue / to.factor;
      }

      return { ok: true, value, type, group, from, to, result };
    }

    function unitConverterFormulaText() {
      const data = unitConvertResultData();
      const type = data.type;
      const groupLabel = (data.group.label || 'medida').toLowerCase();

      if (type === 'temperature') {
        if (data.from.id === data.to.id) return 'mesma escala de temperatura';
        if (data.from.id === 'C' && data.to.id === 'F') return 'multiplique por 9/5 e some 32';
        if (data.from.id === 'F' && data.to.id === 'C') return 'subtraia 32 e multiplique por 5/9';
        if (data.from.id === 'C' && data.to.id === 'K') return 'some 273,15';
        if (data.from.id === 'K' && data.to.id === 'C') return 'subtraia 273,15';
        return 'converta para °C e depois para a unidade desejada';
      }

      const factor = data.from.factor / data.to.factor;
      if (!Number.isFinite(factor)) return '—';
      if (Math.abs(factor - 1) < 1e-12) return 'mesma unidade';

      return 'multiplique o valor de ' + groupLabel + ' por ' + fmt(factor, 8);
    }

    function renderUnitConverterOptions() {
      const type = unitConvType();
      const group = unitConvGroup();
      const from = unitConvUnit('from');
      const to = unitConvUnit('to');
      const data = unitConvertResultData();
      const inputValue = calcValue('unit.value') || '';
      const resultText = data.ok ? fmt(data.result, 8) : '';

      return `
        <section class="unit-google-card">
          <label class="unit-google-type">
            <select id="unitTypeSelect" class="unit-google-select">
              ${Object.keys(UNIT_CONVERTER_GROUPS).map(function (key) {
                const item = UNIT_CONVERTER_GROUPS[key];
                return `<option value="${key}" ${key === type ? 'selected' : ''}>${item.label}</option>`;
              }).join('')}
            </select>
          </label>

          <div class="unit-google-line">
            <button
              class="unit-google-number ${state.calc.activeField === 'unit.value' ? 'active' : ''}"
              data-calc-field="unit.value"
              type="button"
              aria-label="Valor de entrada"
            >${inputValue || '0'}</button>

            <label class="unit-google-unit">
              <select id="unitFromSelect" class="unit-google-select">
                ${group.units.map(function (unit) {
                  return `<option value="${unit.id}" ${unit.id === from.id ? 'selected' : ''}>${unit.label}</option>`;
                }).join('')}
              </select>
            </label>
          </div>

          <div class="unit-google-line">
            <div class="unit-google-number unit-google-output">${resultText || '—'}</div>

            <label class="unit-google-unit">
              <select id="unitToSelect" class="unit-google-select">
                ${group.units.map(function (unit) {
                  return `<option value="${unit.id}" ${unit.id === to.id ? 'selected' : ''}>${unit.label}</option>`;
                }).join('')}
              </select>
            </label>
          </div>

          <div class="unit-google-formula">
            <b>Fórmula</b>
            <span>${unitConverterFormulaText()}</span>
          </div>
        </section>
      `;
    }



