            <div class="biochem-si-note">
              <b>${analyte.category} · Fonte/fator</b>
              <span>${analyte.source || 'Fator curado'} · ${analyte.notes || ''}</span>
              ${warnings.length ? '<ul>' + warnings.map(function (warning) { return '<li>' + warning + '</li>'; }).join('') + '</ul>' : ''}
            </div>
