    function calcCategoryLabel(categoryId) {
      const cat = CALC_CATEGORIES.find(function (item) { return item.id === categoryId; });
      return cat ? cat.label : categoryId;
    }

    function renderCalculatorMenu() {
      const activeCategory = state.calc.category || 'all';
      const visible = activeCategory === 'all'
        ? CALC_LIST
        : CALC_LIST.filter(function (calc) { return calc.category === activeCategory; });

      const grouped = visible.reduce(function (acc, calc) {
        const key = activeCategory === 'all' ? calc.category : calc.group;
        if (!acc[key]) acc[key] = [];
        acc[key].push(calc);
        return acc;
      }, {});

      const categoryOrder = activeCategory === 'all'
        ? CALC_CATEGORIES.filter(function (cat) { return cat.id !== 'all'; }).map(function (cat) { return cat.id; })
        : Object.keys(grouped);

      grid.innerHTML = `
        <section class="calc-home">
          <nav class="calc-category-bar">
            ${CALC_CATEGORIES.map(function (cat) {
              return `<button class="calc-category-chip ${activeCategory === cat.id ? 'active' : ''}" data-calc-category="${cat.id}" type="button">${cat.label}</button>`;
            }).join('')}
          </nav>

          ${categoryOrder.map(function (categoryId) {
            const items = grouped[categoryId] || [];
            if (!items.length) return '';

            return `
              <section class="calc-category-section">
                <div class="calc-category-title">
                  <span>${activeCategory === 'all' ? calcCategoryLabel(categoryId) : categoryId}</span>
                  <span>${items.length}</span>
                </div>

                <div class="calc-category-grid">
                  ${items.map(function (calc) {
                    return `
                      <button class="calc-choice ${calc.category || ''} ${calc.extra ? 'lab-extra' : ''}" data-calc-open="${calc.id}" type="button">
                        <small>${calc.group}</small>
                        <b>${calc.title}</b>
                        <span>${calc.desc}</span>
                        <em class="calc-acronym">${CALC_ACRONYMS[calc.id] || ''}</em>
                      </button>
                    `;
                  }).join('')}
                </div>
              </section>
            `;
          }).join('')}
        </section>
      `;

      Array.prototype.forEach.call(grid.querySelectorAll('[data-calc-category]'), function (btn) {
        btn.addEventListener('click', function () {
          setCalcCategory(this.getAttribute('data-calc-category'));
        });
      });

      Array.prototype.forEach.call(grid.querySelectorAll('[data-calc-open]'), function (btn) {
        btn.addEventListener('click', function () {
          selectCalc(this.getAttribute('data-calc-open'));
        });
      });
    }


