    function manualPlainText(htmlText) {
      const div = document.createElement('div');
      div.innerHTML = htmlText || '';
      return (div.textContent || div.innerText || '').replace(/\s+/g, ' ').trim();
    }

    function escapeRegex(text) {
      return String(text || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    }

    function escapeHtml(text) {
      return String(text || '')
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#39;');
    }

    function manualSnippet(text, query) {
      const clean = String(text || '').replace(/\s+/g, ' ').trim();
      const q = String(query || '').trim();
      if (!clean) return '';
      const lower = clean.toLowerCase();
      const idx = lower.indexOf(q.toLowerCase());
      const start = idx >= 0 ? Math.max(0, idx - 90) : 0;
      const end = Math.min(clean.length, start + 260);
      let snippet = clean.slice(start, end);
      if (start > 0) snippet = '…' + snippet;
      if (end < clean.length) snippet += '…';

      const safe = escapeHtml(snippet);
      if (!q) return safe;

      const rx = new RegExp('(' + escapeRegex(q) + ')', 'ig');
      return safe.replace(rx, '<mark class="manual-hit">$1</mark>');
    }

    function manualSearchResults(query) {
      const q = String(query || '').trim();
      if (q.length < 2) return null;

      const terms = q.toLowerCase().split(/\s+/).filter(Boolean);

      const results = MANUAL_SECTIONS.map(function (section) {
        const htmlBody = manualContent(section.id);
        const plain = manualPlainText(htmlBody);
        const lower = plain.toLowerCase();
        let score = 0;

        terms.forEach(function (term) {
          let pos = lower.indexOf(term);
          while (pos !== -1) {
            score += 1;
            pos = lower.indexOf(term, pos + term.length);
          }
        });

        if (section.title.toLowerCase().indexOf(q.toLowerCase()) !== -1) score += 5;

        return {
          id: section.id,
          title: section.title,
          score: score,
          text: plain
        };
      }).filter(function (item) {
        return item.score > 0;
      }).sort(function (a, b) {
        return b.score - a.score || a.title.localeCompare(b.title);
      });

      if (!results.length) {
        return '<h2>Busca no manual</h2>' +
          '<p class="manual-search-status">Termo pesquisado: <b>' + escapeHtml(q) + '</b></p>' +
          '<div class="manual-empty"><b>Nenhum resultado encontrado.</b><br>Tente termos mais gerais, como “blasto”, “Fuchs”, “cristais”, “UFC”, “hemácia”, “cilindro”, “LDL”, “FENa” ou “timer”.</div>';
      }

      return '<h2>Busca no manual</h2>' +
        '<p class="manual-search-status">' + results.length + ' seção(ões) encontrada(s) para <b>' + escapeHtml(q) + '</b>. Toque em um resultado para abrir a seção correspondente.</p>' +
        '<div class="manual-search-results">' +
          results.map(function (item) {
            return '<button class="manual-search-card" type="button" data-manual-search-section="' + item.id + '">' +
              '<small>Relevância ' + item.score + '</small>' +
              '<b>' + escapeHtml(item.title) + '</b>' +
              '<span>' + manualSnippet(item.text, q) + '</span>' +
            '</button>';
          }).join('') +
        '</div>';
    }

    function renderManualModule() {
      grid.className = 'grid calc-grid';
      const active = state.manual.active || 'inicio';
      const query = state.manual.query || '';
      const searchHtml = manualSearchResults(query);

      grid.innerHTML = `
        <section class="manual-panel">
          <div class="manual-layout">
            <nav class="manual-nav">
              <div class="manual-searchbar">
                <input id="manualSearchInput" type="search" inputmode="search" autocomplete="off" placeholder="Buscar no manual..." value="${escapeHtml(query)}" />
                <button class="btn" data-manual-clear-search type="button">Limpar</button>
              </div>
              ${MANUAL_SECTIONS.map(function (section) {
                return `<button class="btn ${active === section.id && !query ? 'active' : ''}" data-manual-section="${section.id}" type="button">${section.title}</button>`;
              }).join('')}
            </nav>
            <article class="manual-content">${searchHtml || manualContent(active)}</article>
          </div>
        </section>
      `;

      const searchInput = grid.querySelector('#manualSearchInput');
      if (searchInput) {
        searchInput.addEventListener('input', function () {
          state.manual.query = this.value || '';
          renderManualModule();
          const nextInput = grid.querySelector('#manualSearchInput');
          if (nextInput) {
            nextInput.focus();
            const length = nextInput.value.length;
            try { nextInput.setSelectionRange(length, length); } catch (e) {}
          }
        });
      }

      const clearBtn = grid.querySelector('[data-manual-clear-search]');
      if (clearBtn) {
        clearBtn.addEventListener('click', function () {
          state.manual.query = '';
          beep('short');
          renderManualModule();
        });
      }

      Array.prototype.forEach.call(grid.querySelectorAll('[data-manual-section]'), function (btn) {
        btn.addEventListener('click', function () {
          setManualSection(this.getAttribute('data-manual-section'));
        });
      });

      Array.prototype.forEach.call(grid.querySelectorAll('[data-manual-search-section]'), function (btn) {
        btn.addEventListener('click', function () {
          const sectionId = this.getAttribute('data-manual-search-section');
          state.manual.query = '';
          setManualSection(sectionId);
        });
      });
    }


