    function renderSimpleCalcBody(output) {
      const expr = calcValue('simple.expr');

      return `
        <div
          class="calc-expression-display ${state.calc.activeField === 'simple.expr' ? 'active' : ''}"
          data-calc-field="simple.expr"
        >${expr || '0'}</div>

        <div class="calc-result-main">${output.main}</div>
        <p class="calc-note">Toque no visor e use o teclado próprio. Operadores: +, −, ×, ÷, %, ^ e parênteses.</p>
      `;
    }

    function renderClinicalCalcBody(calcId, output) {
      const fields = (calcId === 'unitConv' || calcId === 'biochemSI') ? [] : (CALC_FIELDS[calcId] || []);
      const sex = calcValue('egfr.sex') || 'M';

      if (calcId === 'unitConv') {
        return `
          ${renderUnitConverterOptions()}
          <p class="calc-note unit-google-note">${output.note}</p>
        `;
      }

      if (calcId === 'biochemSI') {
        return `
          ${renderBiochemSIOptions()}
          <p class="calc-note unit-google-note">${output.note}</p>
        `;
      }

      return `
        <div class="field-grid calc-fields">
          ${fields.map(field => `
            <div class="field calc-field">
              <label>${field.label}</label>
              <input
                readonly
                inputmode="none"
                class="${state.calc.activeField === field.id ? 'active' : ''}"
                value="${calcValue(field.id)}"
                data-calc-field="${field.id}"
                placeholder="—"
              />
            </div>
          `).join('')}

          ${calcId === 'egfr' ? `
            <div class="field calc-field">
              <label>Sexo</label>
              <div class="option-row">
                <button class="btn ${sex === 'M' ? 'active' : ''}" id="egfrSexM" type="button">M</button>
                <button class="btn ${sex === 'F' ? 'active' : ''}" id="egfrSexF" type="button">F</button>
              </div>
            </div>
          ` : ''}

          ${calcId === 'cockcroft' ? `
            <div class="field calc-field">
              <label>Sexo</label>
              <div class="option-row">
                <button class="btn ${(calcValue('cg.sex') || 'M') === 'M' ? 'active' : ''}" id="cgSexM" type="button">M</button>
                <button class="btn ${(calcValue('cg.sex') || 'M') === 'F' ? 'active' : ''}" id="cgSexF" type="button">F</button>
              </div>
            </div>
          ` : ''}

          ${calcId === 'ddimer' ? `
            <div class="field calc-field">
              <label>Entrada</label>
              <div class="option-row">
                <button class="btn ${(calcValue('dd.unit') || 'FEU') === 'FEU' ? 'active' : ''}" id="ddFEU" type="button">FEU</button>
                <button class="btn ${(calcValue('dd.unit') || 'FEU') === 'DDU' ? 'active' : ''}" id="ddDDU" type="button">DDU</button>
              </div>
            </div>
          ` : ''}
        </div>

        <div class="calc-output v18">${output.html}</div>
        <p class="calc-note">${output.note}</p>
      `;
    }

    function renderCalcKeypad(isSimple) {
      const base = ['7','8','9','⌫','4','5','6','C','1','2','3','±','0',',','.','OK'];
      const ops = ['+','−','×','÷','(',')','^','%'];

      const keys = isSimple ? [...base, ...ops, '='] : base;

      return keys.map(key => {
        const klass =
          key === 'C' || key === '⌫' ? 'danger' :
          key === 'OK' || key === '=' ? 'good' :
          ['+','−','×','÷','(',')','^','%','±'].includes(key) ? 'op' : '';

        return `<button class="keypad-btn ${klass}" data-calc-key="${key}" type="button">${key}</button>`;
      }).join('');
    }

    function handleCalcKey(key) {
      const active = state.calc.activeField;
      if (!active) return;

      let value = calcValue(active);

      if (key === 'OK' || key === '=') {
        if (state.calc.active === 'simple') {
          const result = safeEvalExpression(value);
          if (result !== 'Erro' && result !== '') setCalcValue(active, String(result).replace(/\./g, ','));
        } else {
          moveToNextCalcField();
        }
        beep('short');
        renderKeys();
        return;
      }

      if (key === 'C') {
        setCalcValue(active, '');
        beep('short');
        renderKeys();
        return;
      }

      if (key === '⌫') {
        setCalcValue(active, value.slice(0, -1));
        beep('short');
        renderKeys();
        return;
      }

      if (key === '±') {
        if (value.startsWith('-')) value = value.slice(1);
        else value = '-' + value;
        setCalcValue(active, value);
        beep('short');
        renderKeys();
        return;
      }

      if (state.calc.active === 'simple') {
        const scientificMap = {
          sin: 'sin(',
          cos: 'cos(',
          tan: 'tan(',
          log: 'log(',
          ln: 'ln(',
          sqrt: 'sqrt(',
          square: '^2',
          power: '^',
          pi: 'π',
          econst: 'e',
          exp: '*10^',
          fact: '!'
        };

        if (key === 'inverse') {
          setCalcValue(active, value ? '1/(' + value + ')' : '1/(');
          beep('short');
          renderKeys();
          return;
        }

        if (Object.prototype.hasOwnProperty.call(scientificMap, key)) {
          setCalcValue(active, value + scientificMap[key]);
          beep('short');
          renderKeys();
          return;
        }
      }

      const mapped = key
        .replace('−', '-')
        .replace('×', '*')
        .replace('÷', '/');

      if (state.calc.active !== 'simple' && !/[0-9,.]/.test(mapped)) return;

      setCalcValue(active, value + mapped);
      beep('short');
      renderKeys();
    }

    function moveToNextCalcField() {
      const fields = (state.calc.active === 'unitConv' || state.calc.active === 'biochemSI') ? [] : (CALC_FIELDS[state.calc.active] || []);
      const idx = fields.findIndex(field => field.id === state.calc.activeField);
      const next = fields.length ? fields[(idx + 1) % fields.length] : null;
      if (next) state.calc.activeField = next.id;
    }

    function calcOutput(calcId) {
      if (calcId === 'simple') {
        const result = safeEvalExpression(calcValue('simple.expr'));
        return { main: result || '0' };
      }

      if (calcId === 'unitConv') {
        const type = unitConvType();

        return {
          html: '',
          note: type === 'concentration'
            ? 'Converte apenas massa/volume equivalentes. Não converte mg/dL para mmol/L sem peso molecular.'
            : 'Escolha o tipo de medida, digite o valor e selecione as unidades de origem e destino.'
        };
      }

      if (calcId === 'biochemSI') {
        const warnings = biochemAdvancedWarnings();
        return {
          html: '',
          note: 'Conversão por fator específico do analito. ' + (warnings[0] || 'Confira unidade, método e faixa de referência.')
        };
      }

      if (calcId === 'ag') {
        const na = calcNum('ag.na');
        const cl = calcNum('ag.cl');
        const hco3 = calcNum('ag.hco3');
        const alb = calcNum('ag.alb');
        let html = '';
        if (Number.isFinite(na) && Number.isFinite(cl) && Number.isFinite(hco3)) {
          const ag = na - (cl + hco3);
          html += line('Ânion gap', `${fmt(ag, 1)} mmol/L`);
          if (Number.isFinite(alb)) {
            html += line('AG corrigido', `${fmt(ag + 2.5 * (4 - alb), 1)} mmol/L`);
          }
        }
        return { html: html || line('Resultado', '—'), note: 'AG = Na − (Cl + HCO₃). AG corrigido = AG + 2,5 × (4 − albumina).' };
      }

      if (calcId === 'osm') {
        const na = calcNum('osm.na');
        const glu = calcNum('osm.glu');
        const urea = calcNum('osm.urea');
        const corrNa = calcNum('osm.corrna');
        let html = '';
        if (Number.isFinite(na) && Number.isFinite(glu) && Number.isFinite(urea)) {
          html += line('Osmolaridade calc', `${fmt((2 * na) + (glu / 18) + (urea / 6), 1)} mOsm/kg`);
        }
        if (Number.isFinite(corrNa) && Number.isFinite(glu)) {
          html += line('Na corrigido', `${fmt(corrNa + 1.6 * ((glu - 100) / 100), 1)} mmol/L`);
        }
        return { html: html || line('Resultado', '—'), note: 'Osm calc ≈ 2Na + glicose/18 + ureia/6. Na corrigido = Na + 1,6×((glicose−100)/100).' };
      }

      if (calcId === 'calcium') {
        const ca = calcNum('ca.ca');
        const alb = calcNum('ca.alb');
        let html = '';
        if (Number.isFinite(ca) && Number.isFinite(alb)) {
          html += line('Ca corrigido', `${fmt(ca + 0.8 * (4 - alb), 2)} mg/dL`);
        }
        return { html: html || line('Resultado', '—'), note: 'Ca corrigido = Ca + 0,8 × (4 − albumina).' };
      }

      if (calcId === 'egfr') {
        const scr = calcNum('egfr.creat');
        const age = calcNum('egfr.age');
        const sex = calcValue('egfr.sex') || 'M';
        let html = '';
        if (Number.isFinite(scr) && scr > 0 && Number.isFinite(age) && age > 0) {
          const female = sex === 'F';
          const k = female ? 0.7 : 0.9;
          const alpha = female ? -0.241 : -0.302;
          const egfr = 142 *
            Math.pow(Math.min(scr / k, 1), alpha) *
            Math.pow(Math.max(scr / k, 1), -1.200) *
            Math.pow(0.9938, age) *
            (female ? 1.012 : 1);

          html += line('eGFR', `${fmt(egfr, 1)} mL/min/1,73m²`);
        }
        return { html: html || line('Resultado', '—'), note: 'Equação CKD-EPI 2021 por creatinina, sem fator racial.' };
      }

      if (calcId === 'ldl') {
        const ct = calcNum('ldl.ct');
        const hdl = calcNum('ldl.hdl');
        const tg = calcNum('ldl.tg');
        let html = '';
        if (Number.isFinite(ct) && Number.isFinite(hdl) && Number.isFinite(tg)) {
          html += line('LDL estimado', `${fmt(ct - hdl - (tg / 5), 1)} mg/dL`);
          html += line('Não-HDL', `${fmt(ct - hdl, 1)} mg/dL`);
          if (tg >= 400) html += line('Alerta', 'TG ≥ 400');
        }
        return { html: html || line('Resultado', '—'), note: 'LDL = CT − HDL − TG/5. Evitar se TG ≥ 400 mg/dL.' };
      }

      if (calcId === 'gas') {
        const ph = calcNum('gas.ph');
        const pco2 = calcNum('gas.pco2');
        const hco3 = calcNum('gas.hco3');
        const pao2 = calcNum('gas.pao2');
        let fio2 = calcNum('gas.fio2');
        let html = '';
        if (Number.isFinite(hco3)) {
          const winter = 1.5 * hco3 + 8;
          html += line('Winter pCO₂ esperada', `${fmt(winter - 2, 1)}–${fmt(winter + 2, 1)} mmHg`);
        }
        if (Number.isFinite(pao2) && Number.isFinite(fio2) && fio2 > 0) {
          if (fio2 > 1) fio2 = fio2 / 100;
          html += line('Relação P/F', fmt(pao2 / fio2, 0));
        }
        if (Number.isFinite(ph) && Number.isFinite(pco2) && Number.isFinite(hco3)) {
          let primary = 'padrão misto/indefinido';
          if (ph < 7.35 && hco3 < 22) primary = 'acidose metabólica provável';
          else if (ph < 7.35 && pco2 > 45) primary = 'acidose respiratória provável';
          else if (ph > 7.45 && hco3 > 26) primary = 'alcalose metabólica provável';
          else if (ph > 7.45 && pco2 < 35) primary = 'alcalose respiratória provável';
          html += line('Leitura inicial', primary);
        }
        return { html: html || line('Resultado', '—'), note: 'Winter: pCO₂ esperada = 1,5×HCO₃ + 8 ±2. P/F = PaO₂/FiO₂.' };
      }

      if (calcId === 'deltaRatio') {
        const ag = calcNum('delta.ag');
        const hco3 = calcNum('delta.hco3');
        let normalAg = calcNum('delta.normalAg');
        if (!Number.isFinite(normalAg)) normalAg = 12;
        let html = '';
        if (Number.isFinite(ag) && Number.isFinite(hco3) && (24 - hco3) !== 0) {
          const ratio = (ag - normalAg) / (24 - hco3);
          html += line('Delta ratio', fmt(ratio, 2));
          html += line('Delta AG', fmt(ag - normalAg, 2));
          html += line('Delta HCO₃', fmt(24 - hco3, 2));
        }
        return { html: html || line('Resultado', '—'), note: 'Delta ratio = (AG − AG normal)/(24 − HCO₃). Use em acidose metabólica com AG aumentado.' };
      }

      if (calcId === 'aaGradient') {
        let fio2 = calcNum('aa.fio2');
        const pco2 = calcNum('aa.pco2');
        const pao2 = calcNum('aa.pao2');
        let pb = calcNum('aa.pb');
        let rq = calcNum('aa.rq');
        if (fio2 > 1) fio2 = fio2 / 100;
        if (!Number.isFinite(pb)) pb = 760;
        if (!Number.isFinite(rq) || rq <= 0) rq = 0.8;
        let html = '';
        if (Number.isFinite(fio2) && Number.isFinite(pco2) && Number.isFinite(pao2)) {
          const paO2 = fio2 * (pb - 47) - (pco2 / rq);
          const grad = paO2 - pao2;
          html += line('PAO₂ estimada', `${fmt(paO2, 1)} mmHg`);
          html += line('Gradiente A-a', `${fmt(grad, 1)} mmHg`);
        }
        return { html: html || line('Resultado', '—'), note: 'Equação alveolar simplificada: PAO₂ = FiO₂ × (PB − 47) − PaCO₂/RQ. A-a = PAO₂ − PaO₂.' };
      }

      if (calcId === 'acidbaseComp') {
        const ph = calcNum('ab.ph');
        const pco2 = calcNum('ab.pco2');
        const hco3 = calcNum('ab.hco3');
        let html = '';
        if (Number.isFinite(ph)) {
          html += line('Estado do pH', ph < 7.35 ? 'acidemia' : (ph > 7.45 ? 'alcalemia' : 'pH na faixa'));
        }
        if (Number.isFinite(hco3)) {
          if (hco3 < 22) {
            const exp = 1.5 * hco3 + 8;
            html += line('Winter pCO₂ esperado', `${fmt(exp - 2, 1)}–${fmt(exp + 2, 1)} mmHg`);
          }
          if (hco3 > 26) {
            const exp = 0.7 * (hco3 - 24) + 40;
            html += line('Alcalose metab. pCO₂ esperado', `${fmt(exp - 5, 1)}–${fmt(exp + 5, 1)} mmHg`);
          }
        }
        if (Number.isFinite(pco2)) {
          if (pco2 > 45) {
            const d = (pco2 - 40) / 10;
            html += line('Resp. acidose aguda HCO₃', fmt(24 + d * 1, 1));
            html += line('Resp. acidose crônica HCO₃', fmt(24 + d * 3.5, 1));
          }
          if (pco2 < 35) {
            const d = (40 - pco2) / 10;
            html += line('Resp. alcalose aguda HCO₃', fmt(24 - d * 2, 1));
            html += line('Resp. alcalose crônica HCO₃', fmt(24 - d * 5, 1));
          }
        }
        return { html: html || line('Resultado', '—'), note: 'Mostra compensações esperadas. Compare com o valor medido para suspeitar de distúrbio misto.' };
      }

      if (calcId === 'inr') {
        const tp = calcNum('inr.tp');
        const ctrl = calcNum('inr.ctrl');
        const isi = calcNum('inr.isi');
        let html = '';
        if (Number.isFinite(tp) && Number.isFinite(ctrl) && ctrl > 0 && Number.isFinite(isi)) {
          html += line('INR', fmt(Math.pow(tp / ctrl, isi), 2));
        }
        return { html: html || line('Resultado', '—'), note: 'INR = (TP paciente / TP controle)^ISI.' };
      }



      if (calcId === 'wbcCorr') {
        const raw = calcNum('wbc.raw');
        const nrbc = calcNum('wbc.nrbc');
        let html = '';
        if (Number.isFinite(raw) && Number.isFinite(nrbc)) {
          const corrected = raw * 100 / (100 + nrbc);
          html += line('Leucócitos corrigidos', fmt(corrected, 0));
        }
        return { html: html || line('Resultado', '—'), note: 'Leucócitos corrigidos = leucócitos totais × 100 / (100 + eritroblastos por 100 leucócitos).' };
      }

      if (calcId === 'retic') {
        const ret = calcNum('retic.percent');
        const rbc = calcNum('retic.rbc');
        const ht = calcNum('retic.ht');
        const mat = calcNum('retic.maturation');
        let html = '';
        if (Number.isFinite(ret) && Number.isFinite(rbc)) {
          html += line('Retic absoluto', `${fmt((ret / 100) * rbc * 1000000, 0)}/µL`);
        }
        if (Number.isFinite(ret) && Number.isFinite(ht)) {
          const corrected = ret * (ht / 45);
          html += line('Retic corrigido', `${fmt(corrected, 2)}%`);
          if (Number.isFinite(mat) && mat > 0) {
            html += line('IPR aproximado', fmt(corrected / mat, 2));
          }
        }
        return { html: html || line('Resultado', '—'), note: 'Retic absoluto = retic% × hemácias. Retic corrigido = retic% × (Ht/45). IPR ≈ retic corrigido/fator.' };
      }

      if (calcId === 'mentzer') {
        const mcv = calcNum('mentzer.mcv');
        const rbc = calcNum('mentzer.rbc');
        let html = '';
        if (Number.isFinite(mcv) && Number.isFinite(rbc) && rbc > 0) {
          const idx = mcv / rbc;
          html += line('Índice de Mentzer', fmt(idx, 2));
          html += line('Leitura didática', idx < 13 ? 'mais compatível com talassemia menor' : 'mais compatível com ferropriva');
        }
        return { html: html || line('Resultado', '—'), note: 'Mentzer = VCM / hemácias em milhões/µL. Corte didático clássico: <13 talassemia menor; >13 ferropriva.' };
      }

      if (calcId === 'pltEstimate') {
        const avg = calcNum('plt.avg');
        let factor = calcNum('plt.factor');
        if (!Number.isFinite(factor) || factor <= 0) factor = 15000;
        let html = '';
        if (Number.isFinite(avg)) {
          html += line('Plaquetas estimadas', `${fmt(avg * factor, 0)}/µL`);
          html += line('Fator usado', fmt(factor, 0));
        }
        return { html: html || line('Resultado', '—'), note: 'Estimativa = média de plaquetas por campo × fator. Se o fator ficar vazio, usa 15.000 como referência didática; confirmar POP local.' };
      }

      if (calcId === 'fena') {
        const uNa = calcNum('fena.uNa');
        const sNa = calcNum('fena.sNa');
        const uCr = calcNum('fena.uCr');
        const sCr = calcNum('fena.sCr');
        let html = '';
        if ([uNa, sNa, uCr, sCr].every(Number.isFinite) && sNa > 0 && uCr > 0) {
          const result = (uNa * sCr) / (sNa * uCr) * 100;
          html += line('FENa', `${fmt(result, 2)}%`);
        }
        return { html: html || line('Resultado', '—'), note: 'FENa = (Na urina × creat soro) / (Na soro × creat urina) × 100.' };
      }

      if (calcId === 'feurea') {
        const uU = calcNum('feu.uUrea');
        const sU = calcNum('feu.sUrea');
        const uCr = calcNum('feu.uCr');
        const sCr = calcNum('feu.sCr');
        let html = '';
        if ([uU, sU, uCr, sCr].every(Number.isFinite) && sU > 0 && uCr > 0) {
          const result = (uU * sCr) / (sU * uCr) * 100;
          html += line('FEUreia', `${fmt(result, 2)}%`);
        }
        return { html: html || line('Resultado', '—'), note: 'FEUreia = (ureia urina × creat soro) / (ureia soro × creat urina) × 100.' };
      }

      if (calcId === 'acr') {
        const alb = calcNum('acr.alb');
        const cr = calcNum('acr.cr');
        let html = '';
        if (Number.isFinite(alb) && Number.isFinite(cr) && cr > 0) {
          const acr = alb / cr * 100;
          html += line('ACR', `${fmt(acr, 1)} mg/g`);
        }
        return { html: html || line('Resultado', '—'), note: 'ACR mg/g ≈ albumina urinária mg/L ÷ creatinina urinária mg/dL × 100.' };
      }

      if (calcId === 'pcr') {
        const prot = calcNum('pcr.prot');
        const cr = calcNum('pcr.cr');
        let html = '';
        if (Number.isFinite(prot) && Number.isFinite(cr) && cr > 0) {
          const ratio = prot / cr;
          html += line('PCR', `${fmt(ratio, 2)} mg/mg`);
          html += line('Estimativa', `${fmt(ratio, 2)} g/g`);
        }
        return { html: html || line('Resultado', '—'), note: 'PCR mg/mg = proteína urinária mg/dL ÷ creatinina urinária mg/dL. Aproxima g/g.' };
      }

      if (calcId === 'protein24h') {
        const prot = calcNum('prot24.prot');
        const vol = calcNum('prot24.vol');
        let hours = calcNum('prot24.hours');
        if (!Number.isFinite(hours) || hours <= 0) hours = 24;
        let html = '';
        if (Number.isFinite(prot) && Number.isFinite(vol)) {
          const mgPeriod = prot * vol / 100;
          const mg24 = mgPeriod * (24 / hours);
          html += line('Proteína no período', `${fmt(mgPeriod, 1)} mg`);
          html += line('Proteinúria ajustada 24h', `${fmt(mg24, 1)} mg/24h`);
        }
        return { html: html || line('Resultado', '—'), note: 'Proteína mg/dL × volume mL / 100. Se tempo ≠24h, ajusta proporcionalmente.' };
      }

      if (calcId === 'albumin24h') {
        const alb = calcNum('alb24.alb');
        const vol = calcNum('alb24.vol');
        let hours = calcNum('alb24.hours');
        if (!Number.isFinite(hours) || hours <= 0) hours = 24;
        let html = '';
        if (Number.isFinite(alb) && Number.isFinite(vol)) {
          const mgPeriod = alb * (vol / 1000);
          const mg24 = mgPeriod * (24 / hours);
          html += line('Albumina no período', `${fmt(mgPeriod, 1)} mg`);
          html += line('Albuminúria ajustada 24h', `${fmt(mg24, 1)} mg/24h`);
        }
        return { html: html || line('Resultado', '—'), note: 'Albumina mg/L × volume em L. Se tempo ≠24h, ajusta proporcionalmente.' };
      }

      if (calcId === 'cockcroft') {
        const age = calcNum('cg.age');
        const weight = calcNum('cg.weight');
        const creat = calcNum('cg.creat');
        const sex = calcValue('cg.sex') || 'M';
        let html = '';
        if ([age, weight, creat].every(Number.isFinite) && creat > 0) {
          let cg = ((140 - age) * weight) / (72 * creat);
          if (sex === 'F') cg *= 0.85;
          html += line('ClCr estimado', `${fmt(cg, 1)} mL/min`);
        }
        return { html: html || line('Resultado', '—'), note: 'Cockcroft-Gault = ((140−idade)×peso)/(72×creat). Multiplicar por 0,85 em sexo feminino.' };
      }

      if (calcId === 'crclTimed') {
        const ucr = calcNum('crcl.ucr');
        const scr = calcNum('crcl.scr');
        const vol = calcNum('crcl.vol');
        const min = calcNum('crcl.min');
        let html = '';
        if (Number.isFinite(ucr) && Number.isFinite(scr) && Number.isFinite(vol) && Number.isFinite(min) && scr > 0 && min > 0) {
          const crcl = (ucr * vol) / (scr * min);
          html += line('Clearance creatinina', `${fmt(crcl, 1)} mL/min`);
        }
        return { html: html || line('Resultado', '—'), note: 'ClCr = (creatinina urinária × volume urinário) / (creatinina sérica × tempo em minutos).' };
      }

      if (calcId === 'ureaCreat') {
        const urea = calcNum('uc.urea');
        const creat = calcNum('uc.creat');
        let html = '';
        if (Number.isFinite(urea) && Number.isFinite(creat) && creat > 0) {
          const bun = urea / 2.14;
          html += line('Ureia/creat', fmt(urea / creat, 1));
          html += line('BUN calculado', `${fmt(bun, 1)} mg/dL`);
          html += line('BUN/creat', fmt(bun / creat, 1));
        }
        return { html: html || line('Resultado', '—'), note: 'BUN ≈ ureia/2,14. Relação depende de contexto clínico e método.' };
      }

      if (calcId === 'bilirubin') {
        const total = calcNum('bili.total');
        const direct = calcNum('bili.direct');
        let html = '';
        if (Number.isFinite(total) && Number.isFinite(direct)) {
          html += line('Bilirrubina indireta', `${fmt(total - direct, 2)} mg/dL`);
        }
        return { html: html || line('Resultado', '—'), note: 'Bilirrubina indireta = bilirrubina total − bilirrubina direta.' };
      }

      if (calcId === 'agRatio') {
        const tp = calcNum('agr.tp');
        const alb = calcNum('agr.alb');
        let html = '';
        if (Number.isFinite(tp) && Number.isFinite(alb)) {
          const glob = tp - alb;
          html += line('Globulina', `${fmt(glob, 2)} g/dL`);
          if (glob > 0) html += line('Relação A/G', fmt(alb / glob, 2));
        }
        return { html: html || line('Resultado', '—'), note: 'Globulina = proteínas totais − albumina. A/G = albumina/globulina.' };
      }

      if (calcId === 'ironSat') {
        const fe = calcNum('iron.fe');
        let tibc = calcNum('iron.tibc');
        const uibc = calcNum('iron.uibc');
        const transf = calcNum('iron.transf');
        let html = '';
        if ((!Number.isFinite(tibc) || tibc <= 0) && Number.isFinite(fe) && Number.isFinite(uibc)) {
          tibc = fe + uibc;
          html += line('TIBC calculado', `${fmt(tibc, 1)} µg/dL`);
        }
        if ((!Number.isFinite(tibc) || tibc <= 0) && Number.isFinite(transf)) {
          tibc = transf * 1.25;
          html += line('TIBC estimado', `${fmt(tibc, 1)} µg/dL`);
        }
        if (Number.isFinite(fe) && Number.isFinite(tibc) && tibc > 0) {
          html += line('Saturação transferrina', `${fmt((fe / tibc) * 100, 1)}%`);
        }
        if (Number.isFinite(tibc) && Number.isFinite(fe)) {
          html += line('UIBC estimado', `${fmt(tibc - fe, 1)} µg/dL`);
        }
        return { html: html || line('Resultado', '—'), note: 'TSAT = ferro sérico/TIBC ×100. TIBC pode ser informado, calculado por ferro+UIBC ou estimado por transferrina×1,25.' };
      }

      if (calcId === 'homa') {
        const glu = calcNum('homa.glu');
        const ins = calcNum('homa.ins');
        let html = '';
        if (Number.isFinite(glu) && Number.isFinite(ins)) {
          const gluMmol = glu / 18;
          html += line('HOMA-IR', fmt((glu * ins) / 405, 2));
          html += line('QUICKI', fmt(1 / (Math.log10(ins) + Math.log10(glu)), 3));
          html += line('Glicose mmol/L', fmt(gluMmol, 2));
        }
        return { html: html || line('Resultado', '—'), note: 'HOMA-IR = glicose mg/dL × insulina / 405. QUICKI = 1/(log insulina + log glicose).' };
      }

      if (calcId === 'tyg') {
        const tg = calcNum('tyg.tg');
        const glu = calcNum('tyg.glu');
        let html = '';
        if (Number.isFinite(tg) && Number.isFinite(glu) && tg > 0 && glu > 0) {
          html += line('TyG index', fmt(Math.log((tg * glu) / 2), 3));
        }
        return { html: html || line('Resultado', '—'), note: 'TyG = ln[(triglicérides mg/dL × glicose mg/dL)/2].' };
      }

      if (calcId === 'eag') {
        const a1c = calcNum('eag.a1c');
        let html = '';
        if (Number.isFinite(a1c)) {
          html += line('eAG', `${fmt(28.7 * a1c - 46.7, 0)} mg/dL`);
        }
        return { html: html || line('Resultado', '—'), note: 'eAG mg/dL = 28,7 × HbA1c − 46,7.' };
      }

      if (calcId === 'apttRatio') {
        const patient = calcNum('aptt.patient');
        const ctrl = calcNum('aptt.ctrl');
        let html = '';
        if (Number.isFinite(patient) && Number.isFinite(ctrl) && ctrl > 0) {
          html += line('Razão TTPa', fmt(patient / ctrl, 2));
        }
        return { html: html || line('Resultado', '—'), note: 'Razão TTPa = TTPa paciente / TTPa controle.' };
      }

      if (calcId === 'ddimer') {
        const value = calcNum('dd.value');
        const unit = calcValue('dd.unit') || 'FEU';
        let html = '';
        if (Number.isFinite(value)) {
          if (unit === 'FEU') {
            html += line('Entrada', `${fmt(value, 0)} FEU`);
            html += line('Estimado em DDU', `${fmt(value / 2, 0)} DDU`);
          } else {
            html += line('Entrada', `${fmt(value, 0)} DDU`);
            html += line('Estimado em FEU', `${fmt(value * 2, 0)} FEU`);
          }
        }
        return { html: html || line('Resultado', '—'), note: 'Conversão aproximada: FEU ≈ 2 × DDU. Confirmar unidade e método do fabricante.' };
      }

      if (calcId === 'lipidPro') {
        const ct = calcNum('lip.ct');
        const hdl = calcNum('lip.hdl');
        const tg = calcNum('lip.tg');
        const ldl = calcNum('lip.ldl');
        let html = '';
        if (Number.isFinite(ct) && Number.isFinite(hdl) && Number.isFinite(ldl)) {
          html += line('Colesterol remanescente', `${fmt(ct - hdl - ldl, 1)} mg/dL`);
        }
        if (Number.isFinite(tg) && Number.isFinite(hdl) && hdl > 0) {
          html += line('TG/HDL', fmt(tg / hdl, 2));
        }
        if (Number.isFinite(ct) && Number.isFinite(hdl)) {
          html += line('Não-HDL', `${fmt(ct - hdl, 1)} mg/dL`);
        }
        return { html: html || line('Resultado', '—'), note: 'Remanescente = CT − HDL − LDL. TG/HDL é razão auxiliar; não substitui avaliação clínica.' };
      }

      return { html: line('Resultado', '—'), note: '' };
    }

    function renderKeys() {
      syncVisualState();
      if (state.mode === 'atlas') { renderAtlasModule(); return; }
      if (state.mode === 'training') { renderTrainingModule(); return; }
      if (state.mode === 'manual') {
        renderManualModule();
        return;
      }

      if (state.mode === 'calc') {
        renderCalculatorModule();
        return;
      }

      if (state.mode === 'timer') {
        grid.className = 'grid timer-grid';
        grid.innerHTML = `
          <section class="timer-panel">
            <div class="timer-display-large">
              <button id="timerAdjustMain" type="button">
                <span class="timer-mode-big" data-timer-mode>${timerLabel()}</span>
                <span class="timer-time-big" data-timer-text>${formatTimer(timerMs())}</span>
                <span class="timer-hint">Toque no relógio para ajuste manual</span>
              </button>
            </div>

            <section class="timer-presets">
              <button class="btn" id="preset1" type="button">1 min</button>
              <button class="btn" id="preset3" type="button">3 min</button>
              <button class="btn" id="preset5" type="button">5 min</button>
              <button class="btn" id="preset10" type="button">10 min</button>
              <button class="btn good" id="timerStartMain" type="button">${state.timer.running ? 'Pausar' : 'Iniciar'}</button>
              <button class="btn danger" id="timerResetMain" type="button">Zerar</button>
            </section>
          </section>
        `;

        document.getElementById('timerAdjustMain').addEventListener('click', openTimerAdjust);
        document.getElementById('preset1').addEventListener('click', () => setCountdownMinutes(1));
        document.getElementById('preset3').addEventListener('click', () => setCountdownMinutes(3));
        document.getElementById('preset5').addEventListener('click', () => setCountdownMinutes(5));
        document.getElementById('preset10').addEventListener('click', () => setCountdownMinutes(10));
        document.getElementById('timerStartMain').addEventListener('click', toggleTimer);
        document.getElementById('timerResetMain').addEventListener('click', resetTimer);
        return;
      }


      if (state.mode === 'semen') {
        var sn = semenActiveTotal();
        if (semenIsFinal()) {
          var fsN = semenTotal();
          var fsPr = semenProgressive();
          var fsMot = semenTotalMotility();
          var fsIm = state.semen.counts.immotile || 0;
          var fvN = semenVitalityTotal();
          var fvAlive = state.semen.vitalityCounts.alive || 0;
          var fvDead = state.semen.vitalityCounts.dead || 0;
          var fmN = semenMorphTotal();
          var fmNormal = state.semen.morphCounts.normal || 0;
          var fmAbnormal = semenMorphDefectTotal();
          var frN = semenRoundTotal();
          var frCounts = state.semen.roundCounts || makeSemenRoundCounts();
          var fc = semenConcentrationResult();
          var defectsText = SEMEN_MORPH_DEFECT_CELLS.map(function(cell){var v=(state.semen.defectCounts&&state.semen.defectCounts[cell.key])||0; return cell.label + ': ' + v;}).join(' · ');
          grid.className = 'grid semen-grid semen-concentration-grid semen-final-grid';
          grid.innerHTML = '<section class="semen-concentration-panel">' +
            '<article class="semen-conc-card full"><h3>Resumo final integrado</h3><p>Visão consolidada dos módulos do espermograma manual. Use como conferência educacional; resultados quantitativos dependem do POP, câmara, diluição, preparo e critérios locais.</p><div class="semen-final-actions"><button class="btn good" id="copySemenFinalBtn" type="button">Copiar resumo</button></div></article>' +
            '<article class="semen-conc-card"><h3>Motilidade</h3><div class="semen-conc-results">' +
              '<div class="semen-conc-line"><span>Total contado</span><strong>' + fsN + '/' + semenTarget() + '</strong></div>' +
              '<div class="semen-conc-line"><span>Progressivos (PR)</span><strong>' + (fsN?fmt((fsPr/fsN)*100,1)+'%':'—') + ' · ' + fsPr + '</strong></div>' +
              '<div class="semen-conc-line"><span>Motilidade total</span><strong>' + (fsN?fmt((fsMot/fsN)*100,1)+'%':'—') + ' · ' + fsMot + '</strong></div>' +
              '<div class="semen-conc-line"><span>Imóveis</span><strong>' + (fsN?fmt((fsIm/fsN)*100,1)+'%':'—') + ' · ' + fsIm + '</strong></div>' +
            '</div></article>' +
            '<article class="semen-conc-card"><h3>Vitalidade</h3><div class="semen-conc-results">' +
              '<div class="semen-conc-line"><span>Total avaliado</span><strong>' + fvN + '/' + semenTarget() + '</strong></div>' +
              '<div class="semen-conc-line"><span>Vivos</span><strong>' + (fvN?fmt((fvAlive/fvN)*100,1)+'%':'—') + ' · ' + fvAlive + '</strong></div>' +
              '<div class="semen-conc-line"><span>Mortos</span><strong>' + (fvN?fmt((fvDead/fvN)*100,1)+'%':'—') + ' · ' + fvDead + '</strong></div>' +
            '</div></article>' +
            '<article class="semen-conc-card"><h3>Morfologia</h3><div class="semen-conc-results">' +
              '<div class="semen-conc-line"><span>Total avaliado</span><strong>' + fmN + '/' + semenTarget() + '</strong></div>' +
              '<div class="semen-conc-line"><span>Normais</span><strong>' + (fmN?fmt((fmNormal/fmN)*100,1)+'%':'—') + ' · ' + fmNormal + '</strong></div>' +
              '<div class="semen-conc-line"><span>Anormais</span><strong>' + (fmN?fmt((fmAbnormal/fmN)*100,1)+'%':'—') + ' · ' + fmAbnormal + '</strong></div>' +
              '<div class="semen-conc-line"><span>Defeitos</span><strong>' + defectsText + '</strong></div>' +
            '</div></article>' +
            '<article class="semen-conc-card"><h3>Células redondas</h3><div class="semen-conc-results">' +
              '<div class="semen-conc-line"><span>Eventos</span><strong>' + frN + '</strong></div>' +
              '<div class="semen-conc-line"><span>Redondas</span><strong>' + (frCounts.roundCell||0) + '</strong></div>' +
              '<div class="semen-conc-line"><span>Leucócitos prováveis</span><strong>' + (frCounts.likelyLeukocyte||0) + '</strong></div>' +
              '<div class="semen-conc-line"><span>Germinativas / debris</span><strong>' + (frCounts.immatureGerm||0) + ' / ' + (frCounts.debris||0) + '</strong></div>' +
            '</div></article>' +
            '<article class="semen-conc-card"><h3>Concentração</h3><div class="semen-conc-results">' +
              '<div class="semen-conc-line"><span>Média contada</span><strong>' + (fc.mean===null?'—':fmt(fc.mean,1)) + '</strong></div>' +
              '<div class="semen-conc-line"><span>Diferença A/B</span><strong>' + (fc.diffPct===null?'—':fmt(fc.diffPct,1)+'%') + '</strong></div>' +
              '<div class="semen-conc-line"><span>Concentração</span><strong>' + (fc.valid?fmt(fc.millionMl,2)+' M/mL':'—') + '</strong></div>' +
              '<div class="semen-conc-line"><span>Total no ejaculado</span><strong>' + (fc.totalMillion!==null?fmt(fc.totalMillion,1)+' milhões':'—') + '</strong></div>' +
            '</div></article>' +
            '<div class="semen-panel-note semen-conc-card full">Resumo educacional. Conferir volume, viscosidade/liquefação, preparo, câmara, diluição, critérios morfológicos, replicatas e POP antes de qualquer uso formal.</div>' +
          '</section>';
          var copySemenBtn = grid.querySelector('#copySemenFinalBtn');
          if (copySemenBtn) copySemenBtn.addEventListener('click', copySemenFinalSummary);
          return;
        }
        if (semenIsRound()) {
          var roundCounts = state.semen.roundCounts || makeSemenRoundCounts();
          grid.className = 'grid semen-grid semen-round-grid';
          grid.innerHTML = SEMEN_ROUND_CELLS.map(function(cell){
            var value = roundCounts[cell.key] || 0;
            return '<button class="semen-key' + (cell.round ? ' round' : '') + (cell.alert ? ' round-alert' : '') + '" data-semen-key="' + cell.key + '" type="button"><span class="semen-code">' + cell.code + '</span><span class="semen-name">' + cell.label + '</span><span class="semen-note">' + cell.note + '</span><strong class="semen-count">' + value + '</strong></button>';
          }).join('') + '<div class="semen-panel-note">Triagem educacional: células redondas podem incluir leucócitos e células germinativas imaturas. A diferenciação segura pode exigir método complementar, como peroxidase, coloração específica ou POP local.</div>';
          Array.prototype.forEach.call(grid.querySelectorAll('[data-semen-key]'), function(btn){ btn.addEventListener('click', function(){ addCount(this.getAttribute('data-semen-key')); }); });
          return;
        }
        if (semenIsMorphology()) {
          var morphCounts = state.semen.morphCounts || makeSemenMorphCounts();
          var defectCounts = state.semen.defectCounts || makeSemenMorphDefectCounts();
          var abnormalBase = semenMorphDefectTotal();
          var normalValue = morphCounts.normal || 0;
          var normalPct = sn ? fmt((normalValue/sn)*100,1) + '%' : 'Forma normal';
          var abnormalPct = sn ? fmt((abnormalBase/sn)*100,1) + '%' : 'Display';
          var classButtons = '<button class="semen-key normal" data-semen-key="normal" type="button"><span class="semen-code">' + normalPct + '</span><span class="semen-name">Normal</span><span class="semen-note">Cabeça, peça intermediária e cauda sem defeito relevante.</span><strong class="semen-count">' + normalValue + '</strong></button>' +
            '<div class="semen-key abnormal display" aria-live="polite"><span class="semen-code">' + abnormalPct + '</span><span class="semen-name">Anormal</span><span class="semen-note">Display automático: soma dos defeitos marcados.</span><strong class="semen-count">' + abnormalBase + '</strong></div>';
          var defectButtons = SEMEN_MORPH_DEFECT_CELLS.map(function(cell){
            var value = defectCounts[cell.key] || 0;
            var pct = abnormalBase ? fmt((value/abnormalBase)*100,1) + '% dos anormais' : cell.code;
            return '<button class="semen-key defect' + (cell.key==='multiple' ? ' wide' : '') + '" data-semen-defect-key="' + cell.key + '" type="button"><span class="semen-code">' + pct + '</span><span class="semen-name">' + cell.label + '</span><span class="semen-note">' + cell.note + '</span><strong class="semen-count">' + value + '</strong></button>';
          }).join('');
          grid.className = 'grid semen-grid semen-morph-grid';
          grid.innerHTML = classButtons + defectButtons + '<div class="semen-panel-note semen-morph-note">Toque em Normal para formas normais. Toque em qualquer defeito para registrar uma forma anormal. O card Anormal é apenas display automático e não é clicável.</div>';
          Array.prototype.forEach.call(grid.querySelectorAll('[data-semen-key]'), function(btn){ btn.addEventListener('click', function(){ addCount(this.getAttribute('data-semen-key')); }); });
          Array.prototype.forEach.call(grid.querySelectorAll('[data-semen-defect-key]'), function(btn){ btn.addEventListener('click', function(){ addSemenMorphDefect(this.getAttribute('data-semen-defect-key')); }); });
          return;
        }
        var semenCells = semenActiveCells();
        var semenCounts = semenActiveCounts();
        var note = semenIsVitality()
          ? 'Vitalidade: vivo = não corado/membrana íntegra; morto = corado/membrana comprometida. Uso educacional: seguir POP, corante e tempo de leitura.'
          : 'Progressivos = PR rápido + PR lento. Motilidade total = PR rápido + PR lento + NP. Uso educacional: seguir POP e condições pré-analíticas do espermograma.';
        grid.className = 'grid semen-grid';
        grid.innerHTML = semenCells.map(function(cell){
          var value = semenCounts[cell.key] || 0;
          var pct = sn ? fmt((value/sn)*100,1) + '%' : cell.code;
          return '<button class="semen-key' + (cell.hot ? ' hot' : '') + (cell.immobile ? ' immobile' : '') + '" data-semen-key="' + cell.key + '" type="button"><span class="semen-code">' + pct + '</span><span class="semen-name">' + cell.label + '</span><span class="semen-note">' + cell.note + '</span><strong class="semen-count">' + value + '</strong></button>';
        }).join('') + '<div class="semen-panel-note">' + note + '</div>';
        Array.prototype.forEach.call(grid.querySelectorAll('[data-semen-key]'), function(btn){
          btn.addEventListener('click', function(){ addCount(this.getAttribute('data-semen-key')); });
        });
        return;
      }

      if (state.mode === 'baar') {
        var bdone = state.baar.fieldsExamined >= state.baar.targetFields;
        grid.className = 'grid baar-grid';
        grid.innerHTML = '<section class="baar-panel"><div class="baar-field-info"><span class="baar-field-label">Campo <strong>' + (state.baar.fieldsExamined + 1) + '</strong> de ' + state.baar.targetFields + '</span><span class="baar-current-label">Neste campo: <strong class="baar-current-count">' + state.baar.currentField + '</strong></span></div><button class="baar-add-btn' + (bdone ? ' baar-done' : '') + '" id="baarAddBtn" type="button"' + (bdone ? ' disabled' : '') + '><span class="baar-add-symbol">+</span><span class="baar-add-sub">BAAR encontrado</span></button><div class="baar-totals"><span>Total: <strong>' + state.baar.totalBaar + '</strong> BAAR</span></div><button class="btn baar-next-btn' + (bdone ? ' good' : '') + '" id="baarNextBtn" type="button">' + (bdone ? 'Concluído — abra o Resumo' : 'Próximo campo →') + '</button></section>';
        var baarAddBtn = document.getElementById('baarAddBtn');
        var baarNextBtn = document.getElementById('baarNextBtn');
        if (baarAddBtn && !bdone) baarAddBtn.addEventListener('click', addBaarInField);
        if (baarNextBtn && !bdone) baarNextBtn.addEventListener('click', baarNextField);
        return;
      }


      if (state.mode === 'fluids') {
        grid.className = 'fluids-screen';
        const total = fluidTotal();
        const type = fluidType();
        const fuchsLeuko = fuchsCellsPerUl('leukocytes');
        const fuchsRbc = fuchsCellsPerUl('rbcs');

        grid.innerHTML = `
          <section class="fluids-panel fluids-panel-v35">
            <section class="fluids-topbar">
              <label>
                <span>Tipo</span>
                <select id="fluidTypeSelect">
                  ${FLUID_TYPES.map(function (item) {
                    return `<option value="${item.id}" ${item.id === state.fluids.type ? 'selected' : ''}>${item.label}</option>`;
                  }).join('')}
                </select>
              </label>

              <button class="fluids-total-field ${state.fluids.activeField === 'totalNucleated' ? 'active' : ''}" id="fluidTotalField" type="button">
                <span>Nucleadas/µL</span>
                <b>${state.fluids.totalNucleated || '—'}</b>
              </button>

              <div class="fluids-note">${type.note}</div>
            </section>

            <section class="fluids-grid">
              ${FLUID_CELLS.map(function (cell) {
                const value = Number(state.fluids.counts[cell.key]) || 0;
                const pct = total ? fluidPercent(cell.key) : 0;
                const abs = fluidAbsolute(cell.key);
                return `
                  <button class="fluids-key ${cell.hot ? 'hot' : ''}" data-fluid-key="${cell.key}" type="button">
                    <span class="fluids-name">${cell.label}</span>
                    <strong class="fluids-count">${value}</strong>
                    <small>${total ? fmt(pct, 1) + '%' : cell.short}${abs !== null ? ' · ' + fmt(abs, 0) + '/µL' : ''}</small>
                  </button>
                `;
              }).join('')}
            </section>

            <section class="fuchs-panel">
              <header class="fuchs-head">
                <div>
                  <b>Global — Fuchs</b>
                  <span>Leucócitos e hemácias/µL</span>
                </div>
                <button class="btn" id="fuchsUndoBtn" type="button">Sub</button>
                <button class="btn danger" id="fuchsResetBtn" type="button">Zerar</button>
              </header>

              <div class="fuchs-controls">
                <button class="fuchs-config" id="fuchsDilutionBtn" type="button">
                  <span>Diluição</span>
                  <b>${state.fluids.fuchs.dilution || '1'}×</b>
                </button>
                <button class="fuchs-config" id="fuchsAreaModeBtn" type="button">
                  <span>Área</span>
                  <b>${fuchsAreaModeLabel()}</b>
                </button>
                <button class="fuchs-config" id="fuchsAreaCountBtn" type="button">
                  <span>${fuchsAreaMode() === 'field' ? 'Campos' : fuchsAreaMode() === 'quadrant' ? 'Quadrantes' : 'Campos'}</span>
                  <b>${fuchsAreaMode() === 'total' ? '256' : fuchsAreaCount()}${fuchsAreaMode() === 'quadrant' ? '/16' : '/256'}</b>
                </button>
                <div class="fuchs-config passive">
                  <span>Volume</span>
                  <b>${fmt(fuchsVolumeUl(), 3)} µL</b>
                </div>
              </div>

              <div class="fuchs-counts">
                <button class="fuchs-count-card leuko" data-fuchs-add="leukocytes" type="button">
                  <span>Leucócitos</span>
                  <strong>${state.fluids.fuchs.leukocytes || 0}</strong>
                  <small>${fmt(fuchsLeuko, 1)} células/µL</small>
                </button>

                <button class="fuchs-count-card rbc" data-fuchs-add="rbcs" type="button">
                  <span>Hemácias</span>
                  <strong>${state.fluids.fuchs.rbcs || 0}</strong>
                  <small>${fmt(fuchsRbc, 1)} células/µL</small>
                </button>
              </div>
            </section>
          </section>
        `;

        document.getElementById('fluidTypeSelect').addEventListener('change', function () {
          state.fluids.type = this.value;
          beep('short');
          render();
        });

        document.getElementById('fluidTotalField').addEventListener('click', function () {
          state.fluids.activeField = 'totalNucleated';
          openFluidTotalModal();
        });

        document.getElementById('fuchsDilutionBtn').addEventListener('click', function () {
          openFuchsConfigModal('dilution');
        });

        document.getElementById('fuchsAreaModeBtn').addEventListener('click', function () {
          openFuchsConfigModal('areaMode');
        });

        document.getElementById('fuchsAreaCountBtn').addEventListener('click', function () {
          openFuchsConfigModal('areaCount');
        });

        document.getElementById('fuchsUndoBtn').addEventListener('click', undoFuchs);
        document.getElementById('fuchsResetBtn').addEventListener('click', resetFuchs);

        Array.prototype.forEach.call(grid.querySelectorAll('[data-fluid-key]'), function (btn) {
          btn.addEventListener('click', function () {
            addCount(this.getAttribute('data-fluid-key'));
          });
        });

        Array.prototype.forEach.call(grid.querySelectorAll('[data-fuchs-add]'), function (btn) {
          btn.addEventListener('click', function () {
            adjustFuchs(this.getAttribute('data-fuchs-add'), 1);
          });
        });

        return;
      }

      if (state.mode === 'colonies') {
        const cfu = colonyCfuMl();
        const info = colonyCountsForResult();
        const method = state.colonies.method || 'dilution';
        const plateMode = state.colonies.plateMode || 'single';
        const active = state.colonies.activePlate || 'A';

        grid.className = 'grid colonies-grid';
        grid.innerHTML = `
          <section class="colonies-panel">
            <button class="colony-big" id="colonyPlusMain" type="button">
              <span>Toque para cada colônia observada na placa ${plateMode === 'duplicate' ? active : ''}</span>
              <b>${colonyActiveCount()}</b>
              <small>${colonyCountStatusFor(colonyActiveCount())}</small>
            </button>

            <section class="colony-mode-card">
              <div class="colony-mode-row method-row">
                <button class="btn ${method === 'dilution' ? 'active' : ''}" data-colony-method="dilution" type="button">Diluição seriada</button>
                <button class="btn ${method === 'loop' ? 'active' : ''}" data-colony-method="loop" type="button">Alça calibrada</button>
              </div>

              <div class="colony-mode-row plate-row">
                <button class="btn ${plateMode === 'single' ? 'active' : ''}" data-colony-plate-mode="single" type="button">Placa única</button>
                <button class="btn ${plateMode === 'duplicate' ? 'active' : ''}" data-colony-plate-mode="duplicate" type="button">Duplicata</button>
                <button class="btn ${active === 'A' ? 'active' : ''}" data-colony-plate="A" type="button">Placa A ${state.colonies.count || 0}</button>
                <button class="btn ${active === 'B' ? 'active' : ''}" data-colony-plate="B" type="button" ${plateMode !== 'duplicate' ? 'disabled' : ''}>Placa B ${state.colonies.countB || 0}</button>
              </div>

              <div class="colony-mode-row range-row">
                ${[[15,300],[25,250],[30,300]].map(r => `
                  <button class="btn ${Number(state.colonies.rangeMin) === r[0] && Number(state.colonies.rangeMax) === r[1] ? 'active' : ''}" data-colony-range="${r[0]}-${r[1]}" type="button">${r[0]}–${r[1]}</button>
                `).join('')}
              </div>
            </section>

            <section class="colony-actions">
              <button class="btn good" data-colony-delta="1" type="button">+1</button>
              <button class="btn good" data-colony-delta="5" type="button">+5</button>
              <button class="btn good" data-colony-delta="10" type="button">+10</button>
              <button class="btn" data-colony-delta="-1" type="button">−1</button>
              <button class="btn" data-colony-delta="-5" type="button">−5</button>
              <button class="btn danger" id="colonyZeroBtn" type="button">Zerar</button>
            </section>

            <div class="colony-inline-help">
              ${method === 'loop'
                ? 'Alças visíveis abaixo: escolha 1 uL, 10 uL ou 100 uL. O campo superior mostra o volume em uL.'
                : 'Para usar alças, toque em “Alça calibrada”; os botões 1 uL, 10 uL e 100 uL aparecem abaixo.'}
            </div>

            ${method === 'dilution' ? `
              <section class="colony-presets">
                ${[0,1,2,3,4,5,6].map(exp => `
                  <button class="btn ${String(state.colonies.dilutionExp) === String(exp) ? 'active' : ''}" data-colony-dil="${exp}" type="button">${exp === 0 ? '10⁰' : '10⁻' + exp}</button>
                `).join('')}
                <button class="btn ${String(state.colonies.platedVolume) === '1' ? 'active' : ''}" data-colony-vol="1" type="button">1 mL</button>
                <button class="btn ${String(state.colonies.platedVolume) === '0.1' ? 'active' : ''}" data-colony-vol="0.1" type="button">0,1 mL</button>
              </section>
            ` : `
              <section class="colony-presets">
                <button class="btn ${String(state.colonies.loopVolumeUl) === '1' ? 'active' : ''}" data-colony-loop="1" type="button">Alça 1 uL</button>
                <button class="btn ${String(state.colonies.loopVolumeUl) === '10' ? 'active' : ''}" data-colony-loop="10" type="button">Alça 10 uL</button>
                <button class="btn ${String(state.colonies.loopVolumeUl) === '100' ? 'active' : ''}" data-colony-loop="100" type="button">Alça 100 uL</button>
              </section>
            `}

            <section class="colony-result-card">
              <b>Resultado estimado</b>
              <span>${cfu ? fmt(cfu, 0) + ' UFC/mL' : (method === 'loop' ? 'Escolha a alça e conte as colônias' : 'Informe diluição, volume e conte as colônias')}</span>
              <small>${plateMode === 'duplicate' ? 'Média usada: ' + fmt(info.average, 1) + ' colônias. ' : ''}${colonyFormulaLabel()}</small>
            </section>
          </section>
        `;

        document.getElementById('colonyPlusMain').addEventListener('click', function () { addColonies(1); });

        Array.prototype.forEach.call(grid.querySelectorAll('[data-colony-delta]'), function (btn) {
          btn.addEventListener('click', function () {
            addColonies(parseInt(this.getAttribute('data-colony-delta'), 10));
          });
        });

        Array.prototype.forEach.call(grid.querySelectorAll('[data-colony-method]'), function (btn) {
          btn.addEventListener('click', function () {
            state.colonies.method = this.getAttribute('data-colony-method');
            beep('short');
            render();
          });
        });

        Array.prototype.forEach.call(grid.querySelectorAll('[data-colony-plate-mode]'), function (btn) {
          btn.addEventListener('click', function () {
            state.colonies.plateMode = this.getAttribute('data-colony-plate-mode');
            if (state.colonies.plateMode === 'single') state.colonies.activePlate = 'A';
            beep('short');
            render();
          });
        });

        Array.prototype.forEach.call(grid.querySelectorAll('[data-colony-plate]'), function (btn) {
          btn.addEventListener('click', function () {
            if (this.disabled) return;
            state.colonies.activePlate = this.getAttribute('data-colony-plate');
            beep('short');
            render();
          });
        });

        Array.prototype.forEach.call(grid.querySelectorAll('[data-colony-range]'), function (btn) {
          btn.addEventListener('click', function () {
            const parts = this.getAttribute('data-colony-range').split('-');
            state.colonies.rangeMin = parseInt(parts[0], 10);
            state.colonies.rangeMax = parseInt(parts[1], 10);
            beep('short');
            render();
          });
        });

        Array.prototype.forEach.call(grid.querySelectorAll('[data-colony-dil]'), function (btn) {
          btn.addEventListener('click', function () {
            state.colonies.dilutionExp = this.getAttribute('data-colony-dil');
            beep('short');
            render();
          });
        });

        Array.prototype.forEach.call(grid.querySelectorAll('[data-colony-vol]'), function (btn) {
          btn.addEventListener('click', function () {
            state.colonies.platedVolume = this.getAttribute('data-colony-vol');
            beep('short');
            render();
          });
        });

        Array.prototype.forEach.call(grid.querySelectorAll('[data-colony-loop]'), function (btn) {
          btn.addEventListener('click', function () {
            state.colonies.loopVolumeUl = this.getAttribute('data-colony-loop');
            beep('short');
            render();
          });
        });

        const zero = document.getElementById('colonyZeroBtn');
        if (zero) zero.addEventListener('click', resetCurrent);
        return;
      }

      if (state.mode === 'myelo') {
        const counts = state.myelo.counts;
        grid.className = 'myelo-v31-screen';
        grid.innerHTML = '<section class="myelo-v31-grid" aria-label="Contador de mielograma"></section>';

        const myeloGrid = grid.querySelector('.myelo-v31-grid');

        MYELO_CELLS.forEach(cell => {
          const btn = document.createElement('button');
          btn.type = 'button';
          btn.className = [
            'myelo-v31-key',
            cell.hot ? 'hot' : '',
            cell.group ? 'group-' + cell.group : ''
          ].filter(Boolean).join(' ');

          btn.innerHTML = `
            <span class="myelo-v31-name">${cell.label}</span>
            <strong class="myelo-v31-count">${counts[cell.key]}</strong>
          `;

          btn.addEventListener('click', () => addCount(cell.key));
          myeloGrid.appendChild(btn);
        });

        return;
      }

      const cells = state.mode === 'hemato' ? HEMATO_CELLS : state.mode === 'reticulocytes' ? RETIC_CELLS : URINE_CELLS;
      const counts = state.mode === 'hemato' ? state.hemato.counts : state.mode === 'reticulocytes' ? state.reticulocytes.counts : state.urine.counts;

      grid.className = state.mode === 'urine' ? 'grid urine' : state.mode === 'reticulocytes' ? 'grid retic' : 'grid';
      grid.innerHTML = '';

      cells.forEach(cell => {
        const btn = document.createElement('button');
        btn.type = 'button';
        btn.className = [
          'key',
          cell.hot ? 'hot' : '',
          cell.wide ? 'wide' : '',
          cell.erythroHighlight ? 'erythroblast-key' : ''
        ].filter(Boolean).join(' ');

        btn.innerHTML = `
          <span class="key-name">${cell.label}</span>
          <strong class="key-count">${counts[cell.key]}</strong>
          <span class="key-sub">${cell.sub}</span>
        `;

        btn.addEventListener('click', () => addCount(cell.key));
        grid.appendChild(btn);
      });
    }


    function summaryWarningsHtml(items) {
      if (!items || !items.length) return '';

      return '<section class="summary-alerts">' +
        '<b>Alertas de conferência</b>' +
        '<ul>' + items.map(function (item) {
          return '<li>' + item + '</li>';
        }).join('') + '</ul>' +
      '</section>';
    }

    function moduleWarningsHtml(mode) {
      const warnings = [];

      if (mode === 'hemato') {
        const n = hematoTotal();
        const wbc = parseFloat(String(state.hemato.wbcTotal || '').replace(',', '.'));
        const erythroblasts = state.hemato.counts.erythroblast || 0;

        if (!n) warnings.push('Nenhuma célula leucocitária foi contada ainda.');
        if (n > 0 && n < 100) warnings.push('Contagem abaixo de 100 leucócitos; use como parcial ou continue até o alvo.');
        if (!Number.isFinite(wbc) || wbc <= 0) warnings.push('Leucócitos totais/µL não informados; os valores absolutos não serão calculados.');
        if (erythroblasts > 0) warnings.push('Eritroblastos foram registrados separadamente; confira se o laboratório exige correção do leucócito total.');
      }

      if (mode === 'myelo') {
        const n = myeloTotal();
        const target = state.myelo.target || 500;
        const erythroid = myeloErythroidTotal();
        const blasts = state.myelo.counts.myBlast || 0;
        const blastPct = n ? (blasts / n) * 100 : 0;

        if (!n) warnings.push('Nenhuma célula nucleada medular foi contada ainda.');
        if (n > 0 && n < target) warnings.push('Contagem abaixo do alvo de ' + target + ' células; o resumo é parcial.');
        if (n > 0 && !erythroid) warnings.push('Série eritroide igual a zero; relação M:E não deve ser interpretada sem revisão da lâmina.');
        if (blastPct >= 5) warnings.push('Blastos ≥5% na contagem; revisar morfologia, qualidade do esfregaço e orientação docente/POP.');
        else if (blasts > 0) warnings.push('Blastos registrados; confira critérios morfológicos antes de interpretar.');
      }

      if (mode === 'fluids') {
        warnings.push.apply(warnings, fluidSummaryWarnings());
      }

      if (mode === 'urine') {
        const total = urineTotal();
        const method = urineMethodInfo();

        if (!total) warnings.push('Nenhuma célula urinária foi contada ainda.');
        if (total > 0) warnings.push('Resultado depende do método selecionado: ' + method.label + '. Confira se o preparo e a câmara correspondem ao POP.');
      }

      if (mode === 'colonies') {
        const a = state.colonies.count || 0;
        const b = state.colonies.countB || 0;
        const info = colonyCountsForResult();
        const avg = info.average || 0;
        const min = parseInt(state.colonies.rangeMin || 30, 10);
        const max = parseInt(state.colonies.rangeMax || 300, 10);

        if (!avg) warnings.push('Nenhuma colônia foi contada ainda.');
        if (state.colonies.plateMode === 'duplicate' && (!a || !b)) warnings.push('Modo duplicata ativo, mas uma das placas está zerada; a média pode ficar enviesada.');
        if (avg > 0 && avg < min) warnings.push('Contagem abaixo da faixa configurada (' + min + '–' + max + '); sinalize como baixa contagem ou siga o POP.');
        if (avg > max) warnings.push('Contagem acima da faixa configurada (' + min + '–' + max + '); avaliar placa incontável/confluente ou nova diluição.');
        if (state.colonies.method === 'dilution') {
          if (colonyDilutionValue() === null) warnings.push('Diluição da placa não informada.');
          if (colonyPlatedVolume() === null) warnings.push('Volume plaqueado não informado.');
        }
        if (state.colonies.method === 'loop' && colonyLoopVolumeMl() === null) {
          warnings.push('Volume da alça não informado.');
        }
      }

      return summaryWarningsHtml(warnings);
    }


    function showSummary() {
      if (state.mode === 'hemato') {
        const n = hematoTotal();
        const wbc = parseFloat(String(state.hemato.wbcTotal || '').replace(',', '.'));
        const hasWbc = Number.isFinite(wbc) && wbc > 0;

        const rows = HEMATO_CELLS.map(cell => {
          const cellCount = state.hemato.counts[cell.key] || 0;
          const pctValue = cell.separate ? null : (n ? (cellCount / n) * 100 : 0);
          const absValue = (!cell.separate && hasWbc && n) ? (cellCount / n) * wbc : null;

          return `
            <tr>
              <td>${cell.label}</td>
              <td>${cellCount}</td>
              <td>${cell.separate ? '—' : fmt(pctValue, 1) + '%'}</td>
              <td>${absValue === null ? '—' : fmt(absValue, 0) + '/µL'}</td>
            </tr>
          `;
        }).join('');

        const erythroblasts = state.hemato.counts.erythroblast || 0;

        summaryContent.innerHTML = `
          ${moduleWarningsHtml('hemato')}
          <p class="method-note">
            Diferencial leucocitário manual · células contadas: <strong>${n}</strong>${hasWbc ? ` · leucócitos totais: <strong>${fmt(wbc, 0)}/µL</strong>` : ''}<br>
            Timer: <strong>${timerLabel()} ${formatTimer(timerMs())}</strong>
          </p>

          <table class="summary-table">
            <thead>
              <tr><th>Célula</th><th>N</th><th>%</th><th>Abs.</th></tr>
            </thead>
            <tbody>
              ${rows}
              <tr><th>Total diferencial leucocitário</th><th>${n}</th><th>${percent(n, 100)}</th><th>${hasWbc ? fmt(wbc, 0) + '/µL' : '—'}</th></tr>
            </tbody>
          </table>

          <p class="method-note">
            Foram encontrados <strong>${erythroblasts}</strong> eritroblastos em ${n || 100} células contadas.
            ${hasWbc ? 'Os valores absolutos foram estimados pelo leucócito total informado no HUD.' : 'Informe leucócitos totais no HUD para estimar os valores absolutos.'}
          </p>
        `;
      } else if (state.mode === 'myelo') {
        const n = myeloTotal();
        const rows = MYELO_CELLS.map(cell => `
          <tr>
            <td>${cell.label}</td>
            <td>${state.myelo.counts[cell.key]}</td>
            <td>${percent(state.myelo.counts[cell.key], n)}</td>
          </tr>
        `).join('');

        const myeloid = myeloMyeloidTotal();
        const erythroid = myeloErythroidTotal();
        const blasts = state.myelo.counts.myBlast || 0;
        const plasma = state.myelo.counts.myPlasma || 0;

        summaryContent.innerHTML = `
          <p class="method-note">
            Mielograma diferencial · células nucleadas contadas: <strong>${n}</strong><br>
            Timer: <strong>${timerLabel()} ${formatTimer(timerMs())}</strong>
          </p>

          <table class="summary-table">
            <thead>
              <tr><th>Célula</th><th>N</th><th>%</th></tr>
            </thead>
            <tbody>
              ${rows}
              <tr><th>Total mieloide</th><th>${myeloid}</th><th>${percent(myeloid, n)}</th></tr>
              <tr><th>Total eritroide</th><th>${erythroid}</th><th>${percent(erythroid, n)}</th></tr>
              <tr><th>Relação M:E</th><th colspan="2">${myeloRatioME()}</th></tr>
              <tr><th>Blastos</th><th>${blasts}</th><th>${percent(blasts, n)}</th></tr>
              <tr><th>Plasmócitos</th><th>${plasma}</th><th>${percent(plasma, n)}</th></tr>
            </tbody>
          </table>

          <p class="method-note">
            Megacariócitos, celularidade, ferro, displasia, hemofagocitose e infiltração devem ser descritos à parte.
          </p>
        `;
      } else if (state.mode === 'fluids') {
        const total = fluidTotal();
        const type = fluidType();
        const rows = FLUID_CELLS.map(function (cell) {
          const count = Number(state.fluids.counts[cell.key]) || 0;
          const pct = total ? fluidPercent(cell.key) : 0;
          const abs = fluidAbsolute(cell.key);
          return `
            <tr>
              <td>${cell.label}</td>
              <td>${count}</td>
              <td>${total ? fmt(pct, 1) + '%' : '—'}</td>
              <td>${abs !== null ? fmt(abs, 0) + '/µL' : '—'}</td>
            </tr>
          `;
        }).join('');

        summaryContent.innerHTML = `
          ${moduleWarningsHtml('fluids')}
          <p class="method-note">
            Líquidos biológicos · tipo: <strong>${type.label}</strong> · diferencial: <strong>${total}</strong> células<br>
            Nucleadas/µL: <strong>${state.fluids.totalNucleated || 'não informado'}</strong><br>
            Timer: <strong>${timerLabel()} ${formatTimer(timerMs())}</strong>
          </p>

          <table class="summary-table">
            <thead>
              <tr><th>Elemento</th><th>N</th><th>%</th><th>Abs.</th></tr>
            </thead>
            <tbody>
              ${rows}
              <tr><th>Total diferencial</th><th>${total}</th><th>${total ? '100%' : '—'}</th><th>${state.fluids.totalNucleated || '—'}</th></tr>
            </tbody>
          </table>

          <h3>Contagem global — Fuchs</h3>
          <table class="summary-table">
            <thead>
              <tr><th>Parâmetro</th><th>Bruto</th><th>Resultado</th></tr>
            </thead>
            <tbody>
              <tr><td>Leucócitos</td><td>${state.fluids.fuchs.leukocytes || 0}</td><td>${fmt(fuchsCellsPerUl('leukocytes'), 1)} células/µL</td></tr>
              <tr><td>Hemácias</td><td>${state.fluids.fuchs.rbcs || 0}</td><td>${fmt(fuchsCellsPerUl('rbcs'), 1)} células/µL</td></tr>
              <tr><td>Diluição</td><td colspan="2">${fuchsDilution()}×</td></tr>
              <tr><td>Área contada</td><td colspan="2">${fuchsAreaModeLabel()} · ${fuchsAreaMode() === 'total' ? '256 campos' : fuchsAreaCount() + (fuchsAreaMode() === 'quadrant' ? ' quadrante(s)' : ' campo(s)')}</td></tr>
              <tr><td>Volume contado</td><td colspan="2">${fmt(fuchsVolumeUl(), 3)} µL</td></tr>
            </tbody>
          </table>

          <p class="method-note">
            Fórmula Fuchs: células/µL = células contadas × diluição ÷ volume contado em µL. Na Fuchs-Rosenthal, a câmara total tem 256 campos = 16 quadrantes = 3,2 µL; cada quadrante tem 0,2 µL e cada campo tem 0,0125 µL.
          </p>

          <p class="method-note">
            Uso didático. Conferir por POP, método de contagem, matriz, preparo, coloração e supervisão técnica.
          </p>
        `;
      
      } else if (state.mode === 'colonies') {
        const cfu = colonyCfuMl();
        const dilution = colonyDilutionValue();
        const volume = colonyPlatedVolume();
        const loopMl = colonyLoopVolumeMl();
        const info = colonyCountsForResult();
        const methodLabel = state.colonies.method === 'loop' ? 'Alça calibrada' : 'Diluição seriada';

        summaryContent.innerHTML = `
          <p class="method-note">
            Contador de colônias · método: <strong>${methodLabel}</strong><br>
            Timer: <strong>${timerLabel()} ${formatTimer(timerMs())}</strong>
          </p>

          <table class="summary-table">
            <thead>
              <tr><th>Parâmetro</th><th>Valor</th></tr>
            </thead>
            <tbody>
              <tr><td>Placa A</td><td>${state.colonies.count || 0}</td></tr>
              <tr><td>Placa B</td><td>${state.colonies.plateMode === 'duplicate' ? (state.colonies.countB || 0) : 'não usada'}</td></tr>
              <tr><td>Contagem usada</td><td>${state.colonies.plateMode === 'duplicate' ? fmt(info.average, 1) + ' média' : (state.colonies.count || 0)}</td></tr>
              <tr><td>Faixa contável configurada</td><td>${state.colonies.rangeMin}–${state.colonies.rangeMax}</td></tr>
              <tr><td>Status</td><td>${colonyCountStatus()}</td></tr>
              ${state.colonies.method === 'loop' ? `
                <tr><td>Volume da alça</td><td>${state.colonies.loopVolumeUl || '—'} µL${loopMl ? ' (' + loopMl + ' mL)' : ''}</td></tr>
              ` : `
                <tr><td>Diluição da placa</td><td>${dilution ? colonyDilutionLabel() : '—'}</td></tr>
                <tr><td>Volume plaqueado</td><td>${volume ? volume + ' mL' : '—'}</td></tr>
              `}
              <tr><th>UFC/mL estimado</th><th>${cfu ? fmt(cfu, 0) + ' UFC/mL' : '—'}</th></tr>
            </tbody>
          </table>

          <p class="method-note">
            ${colonyFormulaLabel()}. Use apenas quando método, volume, diluição/alça, incubação e critério de placa contável forem compatíveis com o POP.
          </p>
        `;

      } else if (state.mode === 'semen') {
        var sN = semenTotal();
        var sPrFast = state.semen.counts.prFast || 0;
        var sPrSlow = state.semen.counts.prSlow || 0;
        var sNp = state.semen.counts.np || 0;
        var sIm = state.semen.counts.immotile || 0;
        var sPr = sPrFast + sPrSlow;
        var sMot = sPr + sNp;
        var rows = SEMEN_MOTILITY_CELLS.map(function(cell){ var value = state.semen.counts[cell.key] || 0; return '<tr><td>' + cell.label + '</td><td>' + value + '</td><td>' + (sN ? fmt((value/sN)*100,1) + '%' : '—') + '</td></tr>'; }).join('');
        var vN = semenVitalityTotal();
        var vAlive = state.semen.vitalityCounts.alive || 0;
        var vDead = state.semen.vitalityCounts.dead || 0;
        var vRows = SEMEN_VITALITY_CELLS.map(function(cell){ var value = state.semen.vitalityCounts[cell.key] || 0; return '<tr><td>' + cell.label + '</td><td>' + value + '</td><td>' + (vN ? fmt((value/vN)*100,1) + '%' : '—') + '</td></tr>'; }).join('');
        var mN = semenMorphTotal();
        var mNormal = state.semen.morphCounts.normal || 0;
        var mAbnormal = semenMorphDefectTotal();
        var mRows = '<tr><td>Normal</td><td>' + mNormal + '</td><td>' + (mN ? fmt((mNormal/mN)*100,1) + '%' : '—') + '</td></tr>' + '<tr><td>Anormal</td><td>' + mAbnormal + '</td><td>' + (mN ? fmt((mAbnormal/mN)*100,1) + '%' : '—') + '</td></tr>';
        var dRows = SEMEN_MORPH_DEFECT_CELLS.map(function(cell){ var value = state.semen.defectCounts[cell.key] || 0; return '<tr><td>' + cell.label + '</td><td>' + value + '</td><td>' + (mAbnormal ? fmt((value/mAbnormal)*100,1) + '% dos anormais' : '—') + '</td></tr>'; }).join('');
        var rN = semenRoundTotal();
        var rRows = SEMEN_ROUND_CELLS.map(function(cell){ var value = state.semen.roundCounts && state.semen.roundCounts[cell.key] || 0; return '<tr><td>' + cell.label + '</td><td>' + value + '</td><td>' + (rN ? fmt((value/rN)*100,1) + '%' : '—') + '</td></tr>'; }).join('');
        var cRes = semenConcentrationResult();
        var cRows = '<tr><td>Replicata A</td><td colspan="2">' + (cRes.countA===null?'—':fmt(cRes.countA,0)) + '</td></tr>' +
          '<tr><td>Replicata B</td><td colspan="2">' + (cRes.countB===null?'—':fmt(cRes.countB,0)) + '</td></tr>' +
          '<tr><td>Média contada</td><td colspan="2">' + (cRes.mean===null?'—':fmt(cRes.mean,1)) + '</td></tr>' +
          '<tr><td>Diluição</td><td colspan="2">' + (cRes.dilution===null?'—':fmt(cRes.dilution,2)) + '</td></tr>' +
          '<tr><td>Volume contado</td><td colspan="2">' + (cRes.volumeUl===null?'—':fmt(cRes.volumeUl,4)+' µL') + '</td></tr>' +
          '<tr><th>Concentração</th><th colspan="2">' + (cRes.valid?fmt(cRes.millionMl,2)+' M/mL':'—') + '</th></tr>' +
          '<tr><th>Total no ejaculado</th><th colspan="2">' + (cRes.totalMillion!==null?fmt(cRes.totalMillion,1)+' milhões':'—') + '</th></tr>';
        summaryContent.innerHTML = '<p class="method-note">Espermograma manual · seção ativa: <strong>' + semenActiveLabel() + '</strong><br>Timer: <strong>' + timerLabel() + ' ' + formatTimer(timerMs()) + '</strong></p><table class="summary-table"><thead><tr><th colspan="3">Motilidade · ' + sN + ' de ' + semenTarget() + '</th></tr><tr><th>Categoria</th><th>N</th><th>%</th></tr></thead><tbody>' + rows + '<tr><th>Progressivos (PR)</th><th>' + sPr + '</th><th>' + (sN ? fmt((sPr/sN)*100,1) + '%' : '—') + '</th></tr><tr><th>Motilidade total</th><th>' + sMot + '</th><th>' + (sN ? fmt((sMot/sN)*100,1) + '%' : '—') + '</th></tr><tr><th>Imóveis</th><th>' + sIm + '</th><th>' + (sN ? fmt((sIm/sN)*100,1) + '%' : '—') + '</th></tr></tbody></table><table class="summary-table"><thead><tr><th colspan="3">Vitalidade · ' + vN + ' de ' + semenTarget() + '</th></tr><tr><th>Categoria</th><th>N</th><th>%</th></tr></thead><tbody>' + vRows + '<tr><th>Vivos</th><th>' + vAlive + '</th><th>' + (vN ? fmt((vAlive/vN)*100,1) + '%' : '—') + '</th></tr><tr><th>Mortos</th><th>' + vDead + '</th><th>' + (vN ? fmt((vDead/vN)*100,1) + '%' : '—') + '</th></tr></tbody></table><table class="summary-table"><thead><tr><th colspan="3">Morfologia · ' + mN + ' de ' + semenTarget() + '</th></tr><tr><th>Classificação</th><th>N</th><th>%</th></tr></thead><tbody>' + mRows + '<tr><th>Formas normais</th><th>' + mNormal + '</th><th>' + (mN ? fmt((mNormal/mN)*100,1) + '%' : '—') + '</th></tr><tr><th>Formas anormais</th><th>' + mAbnormal + '</th><th>' + (mN ? fmt((mAbnormal/mN)*100,1) + '%' : '—') + '</th></tr></tbody></table><table class="summary-table"><thead><tr><th colspan="3">Defeitos observados</th></tr><tr><th>Categoria</th><th>N</th><th>Base: anormais</th></tr></thead><tbody>' + dRows + '</tbody></table><table class="summary-table"><thead><tr><th colspan="3">Células redondas / triagem · ' + rN + ' eventos</th></tr><tr><th>Categoria</th><th>N</th><th>% dos eventos</th></tr></thead><tbody>' + rRows + '</tbody></table><table class="summary-table"><thead><tr><th colspan="3">Concentração espermática</th></tr><tr><th>Parâmetro</th><th colspan="2">Resultado</th></tr></thead><tbody>' + cRows + '</tbody></table><p class="method-note">Motilidade: PR = progressivo rápido + progressivo lento; motilidade total = PR + não progressivo. Vitalidade: interpretar conforme método de coloração vital e POP. Morfologia: Anormal é display automático da soma dos defeitos; use Múltiplos quando um mesmo espermatozoide tiver mais de uma região alterada. Células redondas: diferenciação entre leucócitos e células germinativas imaturas pode exigir método complementar, como peroxidase ou coloração específica. Concentração: conferir câmara, diluição, volume contado e replicatas conforme POP. Resultado educacional; conferir preparo, coloração, critério estrito e rotina local.</p>';
      } else if (state.mode === 'reticulocytes') {
        var sRn = reticTotal();
        var sRtgt = state.reticulocytes.target || 1000;
        var sRcnt = state.reticulocytes.counts.reticulocyte || 0;
        var sRmad = state.reticulocytes.counts.rbcMature || 0;
        var sRpct = sRn > 0 ? (sRcnt / sRn * 100) : 0;
        var sRbc = parseFloat(String(state.reticulocytes.rbcTotal || '').replace(',', '.'));
        var sHasRbc = Number.isFinite(sRbc) && sRbc > 0;
        var sAbs = sHasRbc ? Math.round(sRpct / 100 * sRbc) : null;
        summaryContent.innerHTML = '<p class="method-note">Reticulócitos manuais · células contadas: <strong>' + sRn + '</strong> de ' + sRtgt + (sHasRbc ? ' · hemácias totais: <strong>' + sRbc.toLocaleString('pt-BR') + '/µL</strong>' : '') + '</p><table class="summary-table"><thead><tr><th>Parâmetro</th><th>Valor</th></tr></thead><tbody><tr><td>Reticulócitos contados</td><td>' + sRcnt + '</td></tr><tr><td>Hemácias maduras contadas</td><td>' + sRmad + '</td></tr><tr><td>Total contado</td><td>' + sRn + '</td></tr><tr><th>% Reticulócitos</th><th>' + sRpct.toFixed(2) + '%</th></tr><tr><td>Absoluto</td><td>' + (sAbs !== null ? sAbs.toLocaleString('pt-BR') + '/µL' : '—') + '</td></tr></tbody></table><p class="method-note">Referência adultos: 0,5–2,5% (VN laboratorial pode variar). ' + (!sHasRbc ? 'Informe hemácias totais/µL no HUD para calcular o absoluto.' : '') + '</p>';
      } else if (state.mode === 'baar') {
        var sFlds = state.baar.fieldsExamined;
        var sTot = state.baar.totalBaar;
        var sTgt = state.baar.targetFields;
        var sCur = state.baar.currentField;
        var sGrd = baarGrade();
        var sAvg = sFlds > 0 ? (sTot / sFlds).toFixed(2) : '0.00';
        summaryContent.innerHTML = '<p class="method-note">Baciloscopia (BAAR) · método: <strong>Ziehl-Neelsen semiquantitativo</strong><br>Campos examinados: <strong>' + sFlds + '</strong> de ' + sTgt + ' alvo' + (sCur > 0 ? ' · <em>' + sCur + ' BAAR no campo atual (não registrado)</em>' : '') + '</p><table class="summary-table"><thead><tr><th>Parâmetro</th><th>Valor</th></tr></thead><tbody><tr><td>Total de BAAR encontrados</td><td>' + sTot + '</td></tr><tr><td>Campos examinados</td><td>' + sFlds + '</td></tr><tr><td>Média BAAR/campo</td><td>' + sAvg + '</td></tr><tr><th>Resultado</th><th>' + sGrd + '</th></tr></tbody></table><p class="method-note">Escala OMS/PNCT: <b>Negativo</b> (0/100 campos) · <b>Escasso</b> (1–9/100 campos) · <b>1+</b> (10–99/100 campos) · <b>2+</b> (1–10/campo, 50 campos) · <b>3+</b> (>10/campo, 20 campos).<br>Correlacionar com clínica, técnica e preparo da lâmina. Não usar como laudo isolado.</p>';
      } else {
        const l = state.urine.counts.urineLeuko;
        const h = state.urine.counts.urineRbc;
        const method = urineMethodInfo();
        const factor = method.factor;
        const lResult = l * factor;
        const hResult = h * factor;

        summaryContent.innerHTML = `
          ${moduleWarningsHtml('urine')}
          <p class="method-note">
            Método configurado: <span class="method-badge">${method.label}</span><br>
            ${method.note}<br>
            Timer: <strong>${timerLabel()} ${formatTimer(timerMs())}</strong>
          </p>

          <table class="summary-table">
            <thead>
              <tr>
                <th>Parâmetro</th>
                <th>Contagem bruta</th>
                <th>Resultado calculado</th>
              </tr>
            </thead>
            <tbody>
              <tr><td>Leucócitos</td><td>${l}</td><td>${lResult.toLocaleString('pt-BR')} ${method.unit}</td></tr>
              <tr><td>Hemácias</td><td>${h}</td><td>${hResult.toLocaleString('pt-BR')} ${method.unit}</td></tr>
              <tr><th>Total bruto</th><th>${l + h}</th><th></th></tr>
            </tbody>
          </table>

          <p class="muted-note">
            Observação: usar o fator apenas se o preparo, o volume e a área contada forem compatíveis com o método configurado.
          </p>
        `;
      }

      summaryModal.classList.add('show');
      summaryModal.setAttribute('aria-hidden', 'false');
      beep('short');
    }

    function closeModal() {
      summaryModal.classList.remove('show');
      summaryModal.setAttribute('aria-hidden', 'true');
      beep('short');
    }

    function syncVisualState() {
      const mode = state.mode || '';
      const calcActive = state.mode === 'calc' ? (state.calc.active || 'menu') : '';

      document.body.dataset.mode = mode;
      document.body.dataset.calcActive = calcActive;

      document.body.classList.remove(
        'mode-hemato',
        'mode-myelo',
        'mode-urine',
        'mode-colonies',
        'mode-fluids',
        'mode-calc',
        'mode-timer',
        'mode-manual',
        'mode-reticulocytes',
        'mode-baar',
        'mode-semen',
        'mode-atlas',
        'mode-training'
      );

      if (mode) document.body.classList.add('mode-' + mode);
    }

    function render() {
      syncVisualState();
      renderHud();
      renderKeys();
      updateFullscreenButton();
    }

    fullscreenBtn.addEventListener('click', () => enterFullscreen(false));
    closeSummary.addEventListener('click', closeModal);
    closeCalcHelp.addEventListener('click', closeCalcHelpModal);
    closeTimerAdjust.addEventListener('click', closeTimerAdjustModal);
    closeFluidConfig.addEventListener('click', closeFluidConfigModal);
    cancelFluidConfig.addEventListener('click', closeFluidConfigModal);
    applyFluidConfig.addEventListener('click', applyFluidConfigModal);
    applyTimerAdjust.addEventListener('click', applyManualTimer);
    resetTimerAdjust.addEventListener('click', resetManualTimerFromModal);
    manualCronoBtn.addEventListener('click', setManualCronometer);

    summaryModal.addEventListener('click', event => {
      if (event.target === summaryModal) closeModal();
    });

    calcHelpModal.addEventListener('click', event => {
      if (event.target === calcHelpModal) closeCalcHelpModal();
    });

    timerAdjustModal.addEventListener('click', event => {
      if (event.target === timerAdjustModal) closeTimerAdjustModal();
    });

    fluidConfigModal.addEventListener('click', event => {
      if (event.target === fluidConfigModal) closeFluidConfigModal();
    });

    fluidConfigModal.addEventListener('keydown', event => {
      if (event.key === 'Enter') {
        event.preventDefault();
        applyFluidConfigModal();
      }
      if (event.key === 'Escape') {
        event.preventDefault();
        closeFluidConfigModal();
      }
    });

    window.addEventListener('resize', () => {
      updateFullscreenButton();
      if (isLandscape()) scheduleLandscapeFullscreen();
      else stopFullscreenRetries();
    });

    window.addEventListener('orientationchange', () => {
      setTimeout(scheduleLandscapeFullscreen, 80);
      setTimeout(scheduleLandscapeFullscreen, 280);
      setTimeout(scheduleLandscapeFullscreen, 650);
    });

    if (screen.orientation && screen.orientation.addEventListener) {
      screen.orientation.addEventListener('change', () => {
        setTimeout(scheduleLandscapeFullscreen, 80);
        setTimeout(scheduleLandscapeFullscreen, 280);
      });
    }

    if (window.visualViewport) {
      window.visualViewport.addEventListener('resize', () => {
        if (isLandscape()) scheduleLandscapeFullscreen();
      });
    }

    document.addEventListener('fullscreenchange', updateFullscreenButton);
    document.addEventListener('webkitfullscreenchange', updateFullscreenButton);

