          grid.innerHTML=`<section class="quiz-report-panel"><article class="quiz-report-card"><h2>Relatório do quiz</h2><p>Resultado da sessão por área, com explicação de cada resposta.</p><div class="quiz-report-grid"><div class="quiz-report-metric"><span>Acertos</span><strong>${score}</strong></div><div class="quiz-report-metric"><span>Questões</span><strong>${total}</strong></div><div class="quiz-report-metric"><span>Acurácia</span><strong>${acc}%</strong></div></div><div class="quiz-report-actions"><button class="btn" data-training-menu type="button">Menu</button><button class="btn good" data-training-retry type="button">Nova sessão</button><button class="btn" data-copy-quiz-report type="button">Copiar relatório</button></div><h3 style="margin:12px 0 6px;color:var(--accent)">Histórico recente</h3>${quizHistoryHtml72()}</article><section class="quiz-report-list">${state.training.history.map(function(h,idx){return `<article class="quiz-report-item ${h.correct?'correct':'wrong'}"><b>${idx+1}. ${esc(areaLabel(h.area))} · ${esc(levelLabel(h.level))} · ${h.correct?'Acerto':'Erro'}</b><p>${esc(h.prompt)}</p><p><strong>Sua resposta:</strong> ${esc(h.selected)}</p><p><strong>Resposta correta:</strong> ${esc(h.answer)}</p><p><strong>Explicação:</strong> ${esc(h.why)}</p></article>`;}).join('') || '<div class="atlas-warning">Nenhuma questão respondida.</div>'}</section></section>`;
