        Array.prototype.forEach.call(grid.querySelectorAll('[data-training-answer-index]'), function(btn){btn.addEventListener('click', function(){var idx=Number(this.getAttribute('data-training-answer-index')); answerTraining(options[idx]);});}); var menu=grid.querySelector('[data-training-menu]'); if(menu) menu.addEventListener('click', window.trainingBackToMenu); var next=grid.querySelector('[data-training-next-local]'); if(next) next.addEventListener('click', nextTrainingCase);
