    document.addEventListener('click', function (event) {
      var btn = event.target && event.target.closest ? event.target.closest('[data-home-mode]') : null;
      if (!btn) return;
      var mode = btn.getAttribute('data-home-mode');
      if (!mode) return;
      event.preventDefault();
      event.stopPropagation();
      if (typeof selectModule === 'function') {
        selectModule(mode);
      } else if (window.selectModule) {
        window.selectModule(mode);
      }
    }, true);


