        return ATLAS_CELLS.filter(function(c) {
          var areaOk = area === 'all' || (c.area || 'hematology') === area;
          var groupOk = f === 'all' || c.group === f;
          var hay = [c.name,c.tag,c.stage,c.diff,c.clues,c.alerts,c.area].join(' ').toLowerCase();
          return areaOk && groupOk && (!q || hay.indexOf(q) >= 0);
        });
