      /* v3.77 — modo revisão de erros da sessão atual */
      window.startQuizErrorReview = function(){
        try {
          if(!state.training || !state.training.history) return showToast('Sem relatório para revisar');
          var missed = state.training.history.filter(function(h){ return !h.correct; });
          if(!missed.length) return showToast('Nenhum erro nesta sessão');
          var session = missed.map(function(h){
            var src = TRAINING_CASES.find(function(q){ return q.prompt === h.prompt; }) || h;
            var obj = Object.assign({}, src);
            obj.area = obj.area || h.area || 'hematology'; obj.level = obj.level || h.level || 'basico'; obj.why = obj.why || h.why || '';
            obj.options = (obj.options && obj.options.length) ? obj.options : [h.answer, h.selected, 'Revisar critério', 'POP local'].filter(Boolean);
            obj.shuffledOptions = shuffleSmall(obj.options);
            return obj;
          });
          state.training.session = session; state.training.sessionIndex = 0; state.training.selected = null; state.training.answered = false; state.training.score = 0; state.training.totalAnswered = 0; state.training.history = []; state.training.view = 'session'; state.training.area = 'review'; beep('short'); render();
        } catch(e) { showToast('Falha ao iniciar revisão'); }
      };
      function shuffleSmall(a){ var c=a.slice(); for(var i=c.length-1;i>0;i--){ var j=Math.floor(Math.random()*(i+1)); var t=c[i]; c[i]=c[j]; c[j]=t; } return c; }
      var prevRenderTraining = renderTrainingModule;
      renderTrainingModule = function(){
        prevRenderTraining();
        try {
          if(state.mode !== 'training') return;
          if(state.training && state.training.view === 'report') {
            var actions = grid.querySelector('.quiz-report-actions');
            if(actions && !grid.querySelector('[data-review-errors]')) {
              var btn = document.createElement('button'); btn.className = 'btn'; btn.type = 'button'; btn.setAttribute('data-review-errors','1'); btn.textContent = 'Revisar erros'; btn.addEventListener('click', window.startQuizErrorReview); actions.appendChild(btn);
            }
          }
        } catch(e) {}
      };

