    /* v3.89 — revisão acadêmica/profissional do banco do Quiz */
    (function applyQuizAcademicReviewV389(){
      function areaLabel389(id){
        var map = {
          hematology: 'Hematologia',
          microbiology: 'Microbiologia',
          biochemistry: 'Bioquímica',
          urinalysis: 'Urinálise',
          semen: 'Espermograma',
          parasitology: 'Parasitologia'
        };
        return map[id] || 'Ciências laboratoriais';
      }
      function areaContext389(id){
        var map = {
          hematology: 'Em hematologia morfológica e revisão de esfregaço',
          microbiology: 'Em microbiologia clínica e triagem laboratorial',
          biochemistry: 'Em bioquímica clínica e controle pré-analítico/analítico',
          urinalysis: 'Em urinálise e sedimentoscopia',
          semen: 'Em análise seminal/espermograma',
          parasitology: 'Em parasitologia clínica e microscopia de fezes'
        };
        return map[id] || 'Em prática laboratorial';
      }
      function cleanWhitespace389(s){
        return String(s == null ? '' : s).replace(/\s+/g, ' ').replace(/^\s+|\s+$/g, '');
      }
      function stripGeneric389(s){
        s = cleanWhitespace389(s);
        s = s.replace(/\s*Questão educacional;\s*revisar método, POP e contexto antes de uso formal\.?/gi, '');
        s = s.replace(/\s*Questão educacional;\s*revisar método, POP e contexto antes de uso formal\.?/gi, '');
        return cleanWhitespace389(s);
      }
      function extractClue389(prompt){
        var p = cleanWhitespace389(prompt);
        var m;
        m = p.match(/a descrição\s+["“]([^"”]+)["”]\s+favorece/i);
        if (m && m[1]) return cleanWhitespace389(m[1]);
        m = p.match(/Em uma questão de bancada,\s*(.*?)\.\s*Qual/i);
        if (m && m[1]) return cleanWhitespace389(m[1]);
        m = p.match(/Se o enunciado descreve\s*(.*?),\s*escolha/i);
        if (m && m[1]) return cleanWhitespace389(m[1]);
        m = p.match(/critério:\s*(.*?)\??$/i);
        if (m && m[1]) return cleanWhitespace389(m[1]);
        m = p.match(/^\[[^\]]+\]\s*(.*)$/);
        if (m && m[1]) p = cleanWhitespace389(m[1]);
        p = p.replace(/^Qual alternativa corresponde melhor a:\s*/i, '');
        p = p.replace(/^Qual é a melhor classificação\??\s*/i, '');
        p = p.replace(/^Qual é a melhor resposta\??\s*/i, '');
        return cleanWhitespace389(p);
      }
      function buildPrompt389(item){
        var area = item && item.area ? item.area : 'hematology';
        var topic = item && item.topic ? cleanWhitespace389(item.topic) : '';
        var clue = extractClue389(item && item.prompt ? item.prompt : '');
        if (!clue) clue = item && item.answer ? 'critério compatível com ' + item.answer : 'critério laboratorial apresentado';
        var label = areaLabel389(area);
        var ctx = areaContext389(area);
        var topicText = topic ? ' no eixo de ' + topic : '';
        return ctx + topicText + ', considere o achado/critério abaixo: “' + clue + '”. Qual alternativa apresenta a interpretação, classificação ou conduta técnica mais adequada no contexto de ' + label.toLowerCase() + '?';
      }
      function buildWhy389(item, originalWhy){
        var answer = cleanWhitespace389(item && item.answer ? item.answer : '');
        var base = stripGeneric389(originalWhy || '');
        var area = item && item.area ? areaLabel389(item.area) : 'laboratório clínico';
        var prefix = answer ? 'A alternativa correta é “' + answer + '”. ' : '';
        var suffix = ' Em revisão profissional, esse achado deve ser interpretado com método validado, controle de qualidade, critérios morfológicos/analíticos padronizados e POP local; não deve ser usado isoladamente como conclusão diagnóstica.';
        if (!base) base = 'O enunciado descreve o critério técnico associado à alternativa correta.';
        return cleanWhitespace389(prefix + base + ' Área: ' + area + '.' + suffix);
      }
      function normalizeLevel389(level){
        if (level === 'basic') return 'basico';
        if (level === 'intermediate') return 'intermediario';
        if (level === 'advanced') return 'avancado';
        return level || 'basico';
      }
      function reviewBank389(){
        if (!Array.isArray(window.TRAINING_CASES) && typeof TRAINING_CASES === 'undefined') return;
        var bank = (typeof TRAINING_CASES !== 'undefined') ? TRAINING_CASES : window.TRAINING_CASES;
        if (!Array.isArray(bank)) return;
        for (var i = 0; i < bank.length; i++) {
          var item = bank[i];
          if (!item) continue;
          var originalPrompt = item.prompt || '';
          var originalWhy = item.why || '';
          item.level = normalizeLevel389(item.level);
          if (!item.area) item.area = 'hematology';
          if (!item.options || !item.options.length) item.options = item.answer ? [item.answer] : [];
          item.promptOriginalV389 = originalPrompt;
          item.whyOriginalV389 = originalWhy;
          item.prompt = buildPrompt389(item);
          item.why = buildWhy389(item, originalWhy);
          item.review = 'academic-v3.89';
        }
        try {
          window.NYX_QUIZ_REVIEW_INFO = {
            version: 'v3.89',
            reviewed: bank.length,
            note: 'Banco revisado por padronização técnico-acadêmica; recomenda-se validação docente/especialista para uso formal.'
          };
        } catch(e) {}
      }
      reviewBank389();
    })();

