        if (!wrong.length) { showToast('Sem erros para revisar'); return; }
        var session = [];
        var seen = {};
        for (var j=0;j<wrong.length;j++) {
          var original = findQuestionByConcept402(wrong[j].conceptId) || wrong[j];
          var key = original.conceptId || wrong[j].prompt;
          if (seen[key]) continue;
          seen[key] = true;
          session.push(cloneQuestion402(original));
        }
        state.training.view = 'quiz';
        state.training.mode = 'study';
        state.training.session = session;
        state.training.sessionIndex = 0;
        state.training.selected = null;
        state.training.answered = false;
        state.training.score = 0;
